import type { Drill } from "./types";

// Service / mid drills, keyed by module slug — 25 per module.
// Shift lead or store/restaurant/venue manager: running the floor, schedules,
// staff feedback, escalated complaints, reports to the owner or district
// manager, hiring, suppliers. Merged into course.ts.
export const SERVICE_MID_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-svc-mid-01","level":"mid","profession":"service","title":"The cooler is dying","scenario":"The walk-in cooler is running warm and the repair company says the compressor could fail within days. You need the owner to approve an $850 repair today, but your text draft starts with the whole history of the cooler's noises.","task":"Write a 2-3 sentence text to the owner that leads with the approval you need.","tips":["First sentence: the ask and the number.","What happens if they say no comes second, briefly.","History of the noises can wait for the phone call."],"focus":["clarity","impact"],"placeholder":"Need your OK today on an $850 walk-in repair —"},
    {"id":"lead-svc-mid-02","level":"mid","profession":"service","title":"The shift-swap plea in the group chat","scenario":"Two servers called out for Friday night and you need volunteers to pick up shifts. Your group-chat draft opens with three sentences about how tough this week has been before anyone learns what you're asking.","task":"Write a group-chat message that puts the ask in the first line.","tips":["Lead with the shifts you need covered and the pay incentive if there is one.","Sympathy for the tough week is fine — after the ask.","Make replying easy: name the exact shifts and how to claim one."],"focus":["clarity","concision"],"placeholder":"Two Friday dinner shifts open (5-close) — first two to reply get them."},
    {"id":"lead-svc-mid-03","level":"mid","profession":"service","title":"The huddle with one headline","scenario":"Tonight you have a 40-person reservation at 7pm, and if the kitchen and floor aren't synced it will swamp everything else. Your pre-shift huddle notes list nine reminders in no particular order.","task":"Write the first two sentences of your huddle so the one thing that matters tonight comes first.","tips":["Open with the single headline: the 7pm party and what it changes.","The other reminders survive as a quick list afterward.","If staff remember one sentence, make sure it's the right one."],"focus":["structure","impact"]},
    {"id":"lead-svc-mid-04","level":"mid","profession":"service","title":"The sales dip email","scenario":"Weekend sales came in 18% under the same weekend last year, and the district manager will see the numbers Monday. You want to email first, but your draft opens with the weather and a staffing story before the number appears.","task":"Write a 2-3 sentence email that leads with the number and your read on it.","tips":["State the dip in sentence one — they'll see it anyway.","Follow with your one-line explanation, then what you're doing about it.","Getting ahead of bad numbers reads as ownership, not excuse."],"focus":["clarity","impact"],"placeholder":"Weekend sales came in 18% under last year —"},
    {"id":"lead-svc-mid-05","level":"mid","profession":"service","title":"The fryer ticket that buries the urgency","scenario":"One of two fryers is down and Friday is your busiest day. Your message to the maintenance contractor describes the error light, the smell, and the last service visit before mentioning you need someone before Friday.","task":"Rewrite the request so the deadline and the ask come first.","tips":["Lead with: what's broken and by when you need it fixed.","Symptoms and history are diagnostic detail — put them after.","Ask for a confirmed visit time, not 'whenever you can.'"],"focus":["clarity","precision"],"placeholder":"Fryer 2 is down and I need a tech on site before Friday —"},
    {"id":"lead-svc-mid-06","level":"mid","profession":"service","title":"The short delivery call","scenario":"This morning's delivery arrived missing two cases of chicken you need for tonight. You're about to call the supplier rep, and your instinct is to open with small talk and a recap of the order history.","task":"Write your opening two sentences for the call, leading with the problem and what you need.","tips":["First sentence: what was short and what you need delivered today.","Keep the tone even — direct is not the same as angry.","Get a commitment before the call ends: what time, confirmed how."],"focus":["clarity","impact"]},
    {"id":"lead-svc-mid-07","level":"mid","profession":"service","title":"The handover note that hides the live problem","scenario":"You're handing the floor to the closing lead. Most of the shift was smooth, but table 14 had a comped meal after a long wait and the guest may still complain to corporate. Your note starts with the smooth stuff.","task":"Write a handover note that leads with the one live issue they must know.","tips":["First line: the unresolved situation and what to do if it resurfaces.","Everything that went fine can be one sentence at the end.","Write for someone skimming between tasks."],"focus":["structure","clarity"],"placeholder":"Watch for table 14's guest — long wait, meal comped, may escalate."},
    {"id":"lead-svc-mid-08","level":"mid","profession":"service","title":"The resignation you have to relay","scenario":"Your best bartender just gave two weeks' notice, which blows a hole in the holiday schedule. You need to tell the owner, and your draft spends a paragraph on how valued the bartender was before stating the fact.","task":"Write a 2-3 sentence message that leads with the news and your coverage plan.","tips":["Sentence one: who resigned and their last day.","Sentence two: your plan or the decision you need.","The tribute can happen at the goodbye party, not in this message."],"focus":["clarity","structure"],"placeholder":"Dana gave notice today — last day is the 20th."},
    {"id":"lead-svc-mid-09","level":"mid","profession":"service","title":"The game-night staffing ask","scenario":"There's a playoff game Saturday and last time a game night hit, you ran two servers short and lost tables. You want the owner to approve two extra shifts, but your draft relives the last game night in detail first.","task":"Write a message that leads with the ask, then the one-line justification.","tips":["Open with: two extra shifts Saturday, roughly what it costs.","One sentence of evidence from last time is enough.","End with the yes/no you need and by when."],"focus":["clarity","impact"]},
    {"id":"lead-svc-mid-10","level":"mid","profession":"service","title":"The incident report's first line","scenario":"A guest slipped on a wet patch near the bar and declined medical attention, and you have to file an incident report the owner and insurer will read. Your draft opens with the weather and how busy the night was.","task":"Write the first line of the incident report: what happened, when, and current status.","tips":["Lead with the fact: who, what, when, where, outcome.","Context like weather and crowd belongs later, if at all.","Stick to what you saw and were told — no speculation in line one."],"focus":["precision","clarity"],"placeholder":"At 8:40pm a guest slipped near the bar; she declined medical attention and finished her visit."},
    {"id":"lead-svc-mid-11","level":"mid","profession":"service","title":"The 'how's the new hire' reply","scenario":"The owner texts: 'How's Marcus working out?' You have a clear verdict — he's solid on the floor but keeps missing his opening tasks. Your draft reply tells three shift stories before giving any verdict.","task":"Write a reply that gives the verdict first, then one specific.","tips":["Answer the question in the first sentence: keep, coach, or concern.","One concrete example beats three anecdotes.","Say what you're doing about the gap, in a few words."],"focus":["clarity","concision"],"placeholder":"Keeping him — strong on the floor, but I'm coaching him on opening tasks."},
    {"id":"lead-svc-mid-12","level":"mid","profession":"service","title":"The inspection heads-up","scenario":"The health inspector is due sometime in the next two weeks, and the one thing that will sink you is the broken sanitizer gauge on the dish machine. Your team message lists fourteen general cleanliness reminders before mentioning it.","task":"Write a team message that leads with the one critical fix and the timeframe.","tips":["First line: inspection window and the single most important item.","A long list dilutes the one thing that actually fails you.","Assign the critical fix to a name, with a deadline."],"focus":["impact","structure"]},
    {"id":"lead-svc-mid-13","level":"mid","profession":"service","title":"The refund that needs a ruling","scenario":"A customer is demanding a $220 refund for a private-room booking they say was misrepresented. It's above your comfort level and you want the owner's call today. Your draft retells the whole dispute chronologically.","task":"Write a message that leads with the decision you need and your recommendation.","tips":["Open with: I need your call on a $220 refund by end of day.","Give your recommendation in the same breath — don't just forward the problem.","Compress the backstory to two sentences of essentials."],"focus":["clarity","structure"],"placeholder":"Need your call today: $220 refund request on the private room — I'd give half."},
    {"id":"lead-svc-mid-14","level":"mid","profession":"service","title":"The schedule change nobody should miss","scenario":"Starting next week, the store opens an hour earlier on Saturdays, which changes three people's shifts. Your group-chat draft explains the business reasoning for two paragraphs before stating the change.","task":"Write an announcement where the change itself is the first sentence.","tips":["Lead with what changes and when it starts.","Name the people affected so they can't miss it.","The why can be one sentence — most people just need the what."],"focus":["clarity","concision"],"placeholder":"Starting Saturday the 12th we open at 8am — that shifts three schedules:"},
    {"id":"lead-svc-mid-15","level":"mid","profession":"service","title":"The shrinkage spike","scenario":"This month's inventory count shows shrinkage at 4.1%, more than double your usual. The district manager needs to hear it from you before the report lands. Your draft opens by describing your counting process.","task":"Write a 2-3 sentence heads-up that leads with the number.","tips":["State the figure and the comparison in sentence one.","Your leading theory and next step follow.","Proving your process was sound is a defensive opener — skip it."],"focus":["precision","impact"],"placeholder":"Shrinkage hit 4.1% this month, up from our usual 1.8% —"},
    {"id":"lead-svc-mid-16","level":"mid","profession":"service","title":"The POS repair request","scenario":"Register 2 freezes during rushes and the vendor quoted $400 to replace the terminal. You need district approval. Your email draft walks through every freeze incident of the past month before naming the cost.","task":"Write an email opening that leads with the ask and the cost.","tips":["Sentence one: approve $400 to replace register 2's terminal.","Sentence two: the cost of not doing it, in lost-transaction terms.","Incident details go in an attachment or a short list below."],"focus":["clarity","impact"]},
    {"id":"lead-svc-mid-17","level":"mid","profession":"service","title":"The recall pull","scenario":"Your distributor just emailed a recall notice for a batch of pre-cut lettuce you have in stock. Staff need to pull it now, mid-shift. Your message draft starts by summarizing the distributor's email.","task":"Write a group-chat message where the action is the first line.","tips":["First words: pull the item — name, batch, where it lives.","Say what to do with it once pulled.","The recall backstory is one trailing sentence at most."],"focus":["clarity","impact"],"placeholder":"Pull all bagged romaine from the walk-in now — recall on lot 4471."},
    {"id":"lead-svc-mid-18","level":"mid","profession":"service","title":"The 'are we ready?' answer","scenario":"The owner texts: 'Are we set for the private event Saturday?' You are — staffing confirmed, menu finalized, deposit paid — except the linen order arrives Friday and could slip. Your draft reply lists every arrangement chronologically.","task":"Write a reply that answers yes/no first, then flags the one open risk.","tips":["First word: yes (or no). Then the single caveat.","Don't recite the checklist — they asked for a verdict.","Say what you'll do if the linens slip, in one clause."],"focus":["concision","clarity"],"placeholder":"Yes — one open item: linens land Friday, and if they slip I'll..."},
    {"id":"lead-svc-mid-19","level":"mid","profession":"service","title":"The time-off ruling","scenario":"A cook requested next Friday off three weeks ago and keeps asking. You've decided: yes, with a swap you've already arranged. Your message to him opens with a long explanation of how hard the decision was.","task":"Write a reply that gives the decision in the first sentence.","tips":["Lead with the answer: approved, and who's covering.","People want the ruling, not the deliberation.","If there's a condition, state it right after the yes."],"focus":["clarity","concision"]},
    {"id":"lead-svc-mid-20","level":"mid","profession":"service","title":"The short till","scenario":"Tonight's till came up $60 short. You've recounted twice and checked the no-sales log; nothing obvious. The owner needs to know tonight. Your draft opens with reassurances about how honest your team is.","task":"Write a 2-3 sentence message that leads with the fact and where you are in checking it.","tips":["Sentence one: the amount and the shift.","Then: what you've ruled out and your next step.","Don't editorialize about the team either way — report, then investigate."],"focus":["precision","clarity"],"placeholder":"Tonight's till is $60 short after two recounts —"},
    {"id":"lead-svc-mid-21","level":"mid","profession":"service","title":"The Friday recap headline","scenario":"You send the owner a weekly recap. The real story this week: your new lunch combo lifted weekday lunch sales 12%. Your draft opens with a paragraph about the dishwasher repair and a staff birthday.","task":"Write the opening line of the recap that leads with the week's result.","tips":["Lead with the number that matters most.","Repairs and birthdays are the footer, not the headline.","One summary sentence, then short bullets."],"focus":["structure","impact"],"placeholder":"Headline this week: the lunch combo lifted weekday lunch sales 12%."},
    {"id":"lead-svc-mid-22","level":"mid","profession":"service","title":"The policy change announcement","scenario":"From next month, staff meal discounts drop from 100% to 50% — the owner's call, and you have to announce it. Your group-chat draft buries the change under four sentences about food costs.","task":"Write an announcement that states the change and start date in the first line.","tips":["Lead with the change — burying it reads as evasive and people resent it more.","One honest sentence of why.","Say where to bring questions rather than debating in the chat."],"focus":["clarity","impact"]},
    {"id":"lead-svc-mid-23","level":"mid","profession":"service","title":"Borrowing staff from the other store","scenario":"You need to borrow a trained barista from the sister store across town for Sunday morning. You're texting that store's manager, and your draft opens with three sentences of apology for asking.","task":"Write a text that leads with the specific request.","tips":["First sentence: one barista, Sunday 7am-1pm, at your store.","Offer the trade or payback in sentence two.","Managers respect a clean ask more than an apologetic one."],"focus":["clarity","concision"],"placeholder":"Could I borrow one of your baristas this Sunday 7-1?"},
    {"id":"lead-svc-mid-24","level":"mid","profession":"service","title":"The vendor price jump","scenario":"Your produce supplier just announced an 11% price increase effective next month. You've already scoped an alternative supplier at 4% above current prices. Your email to the owner narrates the whole discovery process first.","task":"Write an email opening that leads with the news and your recommendation.","tips":["Sentence one: the increase. Sentence two: your recommended move.","Bring the answer, not just the problem.","Comparison details go below as support."],"focus":["structure","impact"],"placeholder":"Produce prices go up 11% next month — I recommend we switch to..."},
    {"id":"lead-svc-mid-25","level":"mid","profession":"service","title":"The injury follow-up","scenario":"Yesterday a guest slipped and today she called saying her wrist is sore and she's seeing a doctor. The owner heard about the fall but not the call. Your draft update starts by re-describing the original incident.","task":"Write a 2-3 sentence update that leads with what's new.","tips":["Lead with today's development — the owner knows yesterday's story.","State exactly what you told her and what you didn't promise.","Name the next step: incident file updated, insurer contacted."],"focus":["clarity","precision"]}
  ],
  "start-with-the-audience": [
    {"id":"audience-svc-mid-01","level":"mid","profession":"service","title":"The POS outage, explained to the crew","scenario":"The card-payment system will be down for a vendor upgrade from 2-4pm tomorrow. The vendor's email is full of terms like 'gateway migration' and 'tokenization.' Your cashiers just need to know what to do at the register.","task":"Write a 2-3 sentence team message that tells staff what to do, not what the vendor is doing.","tips":["Translate the outage into register behavior: cash only, offline slips, whatever applies.","Cut every vendor term that doesn't change what staff do.","Tell them exactly what to say to customers at the till."],"focus":["audience","clarity"],"placeholder":"Card payments are down 2-4pm tomorrow — here's what to do at the register:"},
    {"id":"audience-svc-mid-02","level":"mid","profession":"service","title":"Food cost, in kitchen terms","scenario":"The owner wants food cost brought down from 34% to 31%, and you need the kitchen's help. Saying 'we need to improve our food cost percentage by 300 basis points' will land as noise. What the cooks control is portioning, waste, and prep quantities.","task":"Write a short huddle message that turns the target into things the kitchen actually does.","tips":["Skip the percentage — name the two or three behaviors that move it.","Make it concrete: portion scoops, prep pars, the waste log.","Give them the stake: what hitting the target protects or unlocks."],"focus":["audience","impact"]},
    {"id":"audience-svc-mid-03","level":"mid","profession":"service","title":"The tech problem, in owner terms","scenario":"The scheduling app keeps double-booking because of a sync bug, and you want the owner to approve switching platforms. Your draft explains API sync failures. The owner cares about one thing: what it's costing and what the fix costs.","task":"Write a 3-4 sentence pitch in money-and-time terms, not tech terms.","tips":["Lead with the cost of the problem: overstaffed hours, missed shifts, your hours lost fixing it.","Name the fix and its price in the same breath.","One sentence of tech detail maximum, and only if it helps them decide."],"focus":["audience","impact"],"placeholder":"The scheduling app's bug cost us about 14 overstaffed hours last month."},
    {"id":"audience-svc-mid-04","level":"mid","profession":"service","title":"Food safety for day-one hires","scenario":"You're briefing two new hires on food safety. The official material cites regulation numbers and terms like 'time/temperature control for safety foods.' They've never worked in food service before.","task":"Write the first four sentences of a briefing in plain words a first-timer can act on.","tips":["Lead with the behaviors: wash hands when, gloves when, what temperature danger means.","Cut the regulation citations — they protect nobody on the line.","Give one memorable rule of thumb they can carry through day one."],"focus":["audience","clarity"]},
    {"id":"audience-svc-mid-05","level":"mid","profession":"service","title":"The menu change, for servers","scenario":"The kitchen is replacing the salmon dish with a trout dish because of supplier costs. The servers don't need the supplier story — they need what to say when a regular orders the salmon tonight.","task":"Write a pre-shift note that arms servers with what customers will ask.","tips":["Anticipate the top two questions: where's the salmon, what's the trout like.","Give servers an exact recommended line, not just facts.","Skip the supplier economics unless a guest specifically asks."],"focus":["audience","clarity"],"placeholder":"Salmon is off the menu from tonight — when guests ask, say:"},
    {"id":"audience-svc-mid-06","level":"mid","profession":"service","title":"The renovation sign","scenario":"The dining room closes for renovation for two weeks; takeout stays open. Your first draft of the door sign explains contractor schedules and permit timing. Customers walking up care about exactly one thing: can I get food, and how.","task":"Write a door sign of 2-3 sentences from the customer's point of view.","tips":["Lead with what they CAN do: takeout open, hours, how to order.","Dates matter; contractor details don't.","End with something warm — you want them back in two weeks."],"focus":["audience","concision"]},
    {"id":"audience-svc-mid-07","level":"mid","profession":"service","title":"The app, for the app-hater","scenario":"Your most reliable veteran server refuses to use the new scheduling app and keeps missing swap notifications. Your first instinct is to re-send the feature walkthrough. What she actually cares about: not being burned by a schedule change she never saw.","task":"Write a short message that sells the app in terms of what she cares about.","tips":["Lead with her stake: never getting surprised by a changed shift.","Reduce the ask to the one function she needs, not the whole app.","Offer the two-minute setup together rather than a manual."],"focus":["audience","impact"]},
    {"id":"audience-svc-mid-08","level":"mid","profession":"service","title":"The DM report at the right altitude","scenario":"Your monthly report to the district manager recounts individual shifts: who called out on the 4th, the printer jam on the 11th. The DM oversees nine locations and reads for trends: sales trajectory, labor percentage, anything needing intervention.","task":"Rewrite your report opening as 3-4 sentences at trend level.","tips":["Report the month, not the shifts: direction of sales, labor, turnover.","One incident earns a mention only if it signals a pattern or needs their help.","Ask yourself: what would I want from nine of these landing at once?"],"focus":["audience","structure"],"placeholder":"October: sales up 6% on last year, labor steady at 29%, one item needs your attention."},
    {"id":"audience-svc-mid-09","level":"mid","profession":"service","title":"Tip pooling, in paycheck terms","scenario":"The restaurant is moving from individual tips to a pooled system. Your draft announcement explains the fairness philosophy and the distribution formula. Every server reading it has one question: what happens to MY money.","task":"Write an announcement that answers the paycheck question first.","tips":["Lead with the concrete effect: a typical server's night, before and after.","Show the math on one realistic example, not the formula in the abstract.","Then the why — fairness arguments land only after the money question is answered."],"focus":["audience","clarity"],"placeholder":"Under the new pool, a typical Friday shift pays out about..."},
    {"id":"audience-svc-mid-10","level":"mid","profession":"service","title":"The order, in supplier terms","scenario":"You're emailing a new supplier your first standing order. Your draft describes your menu and your busy nights. What the supplier's dispatcher needs: exact products, case quantities, delivery days, dock hours, and who signs.","task":"Write the order email organized around what the dispatcher needs to fill it.","tips":["Give quantities and delivery windows in a scannable list, not prose.","Name the receiving contact and the dock constraints.","Your menu story is relationship-building — one sentence, then the specifics."],"focus":["audience","precision"]},
    {"id":"audience-svc-mid-11","level":"mid","profession":"service","title":"Allergy protocol for the floor","scenario":"After a near-miss with a peanut allergy, you're rewriting the allergy procedure. The kitchen version talks about cross-contact and dedicated fryers. Servers need a different version: what to ask, what to write on the ticket, who to tell.","task":"Write the server-facing version in 3-4 steps.","tips":["Order the steps by when they happen: at the table, on the ticket, to the kitchen.","Give exact words for the table question.","One rule for when in doubt: flag the manager, every time."],"focus":["audience","structure"],"placeholder":"When a guest mentions any allergy: 1) Ask..."},
    {"id":"audience-svc-mid-12","level":"mid","profession":"service","title":"The note for the overnight crew","scenario":"The contracted overnight cleaning crew keeps missing the prep area behind the line — because your notes say things like 'behind the line' and 'the pass,' terms that mean nothing to people who've never worked a service shift.","task":"Rewrite the cleaning note so someone who has never seen a restaurant kitchen can find and clean the right areas.","tips":["Replace floor slang with physical descriptions: the counter left of the big grill.","Walk the space in the note the way they'd walk it at 2am.","One photo reference beats three sentences — say where you taped it."],"focus":["audience","clarity"]},
    {"id":"audience-svc-mid-13","level":"mid","profession":"service","title":"The promo, at the register","scenario":"Corporate launched a 'buy two, get one 50% off' promotion with a page of terms. Your cashiers don't need the marketing rationale — they need what buttons to press and what to say when the discount doesn't fire.","task":"Write the cashier-facing version of the promo in 3-4 sentences.","tips":["Lead with the register steps, in order.","Cover the one failure case: what to do when it doesn't apply.","Give the one-line answer for 'why isn't this working?' at the till."],"focus":["audience","clarity"]},
    {"id":"audience-svc-mid-14","level":"mid","profession":"service","title":"The HVAC email to the landlord","scenario":"The dining room AC has struggled for two weeks. Your draft to the landlord vents about uncomfortable guests and sweating staff. The landlord acts on lease obligations, dates, temperatures, and documented notice — not discomfort stories.","task":"Write a 3-4 sentence email built from what makes a landlord act.","tips":["Facts that trigger action: dates reported, measured temperatures, lease clause if you know it.","State the specific remedy and a reasonable deadline.","Keep it courteous and documented — this email may be evidence later."],"focus":["audience","precision"],"placeholder":"Following up on the AC issue first reported June 3:"},
    {"id":"audience-svc-mid-15","level":"mid","profession":"service","title":"The slow-line apology to a regular","scenario":"A regular waited 25 minutes for lunch yesterday and mentions it, kindly but pointedly. The true cause involves a no-show cook and a delivery mix-up. She doesn't need your ops story — she needs to know it's not the new normal.","task":"Write (or say) a 2-3 sentence response in customer terms.","tips":["Acknowledge her experience specifically — 25 minutes is long, say so.","One clause of explanation, maximum: yesterday was unusual because X.","Tell her what's true going forward, which is what she's really asking."],"focus":["audience","concision"]},
    {"id":"audience-svc-mid-16","level":"mid","profession":"service","title":"The day-one welcome message","scenario":"You're writing the message new hires get before their first shift. Your current draft assumes context they don't have: 'park in the usual spot,' 'ask for whoever's on.' A nervous 19-year-old reads this the night before, knowing nothing.","task":"Rewrite the welcome message assuming zero prior knowledge.","tips":["Answer the night-before anxieties: where to park, what to wear, who to ask for by name, what the first hour looks like.","Name one person who's expecting them.","Warm and specific beats cheerful and vague."],"focus":["audience","clarity"],"placeholder":"Welcome! Here's everything for Tuesday: park behind the building, ask for..."},
    {"id":"audience-svc-mid-17","level":"mid","profession":"service","title":"Shrinkage, without the accusation","scenario":"Inventory losses are up and you need the whole team's help tightening receiving checks and waste logging. A message that reads as 'someone here is stealing' will poison the room. Most shrinkage is process, and your team's stake is real: losses shrink the bonus pool.","task":"Write a team message that motivates tighter process without implying suspicion.","tips":["Frame around process and shared stake, not suspicion.","Name the two behaviors you're asking for, concretely.","Connect the number to something the team feels — the bonus pool, the hours budget."],"focus":["audience","impact"]},
    {"id":"audience-svc-mid-18","level":"mid","profession":"service","title":"Corporate memo, huddle version","scenario":"Corporate sent a 600-word memo about a new customer-satisfaction initiative, full of phrases like 'guest experience journey optimization.' You have 90 seconds at the pre-shift huddle to make it mean something to your crew.","task":"Write the 3-4 sentence huddle version in your team's language.","tips":["Extract the one behavior corporate actually wants changed.","Translate the metric into what a guest sees and feels.","Say what's in it for the team — scores drive whose numbers?"],"focus":["audience","concision"],"placeholder":"Corporate's new push boils down to one thing for us:"},
    {"id":"audience-svc-mid-19","level":"mid","profession":"service","title":"Why counts matter, to the counter","scenario":"The stocker doing weekly inventory counts rushes them, and the errors ripple into your ordering. Telling him 'inventory accuracy is important' has changed nothing. What might: showing him what his count touches.","task":"Write a short explanation that connects his count to consequences he can see.","tips":["Trace one real error to its result: a miscount led to running out mid-Saturday.","Make him the hero of the accurate version, not the culprit of the sloppy one.","End with the one change you want in how he counts."],"focus":["audience","impact"]},
    {"id":"audience-svc-mid-20","level":"mid","profession":"service","title":"Briefing the event security","scenario":"You've hired two security contractors for a sold-out venue night. Your draft brief describes the artist and the vibe. What security needs: capacity number, ID policy, where trouble usually starts, who makes the eject call, and how to reach you.","task":"Write the security brief organized around their decisions, not your event.","tips":["Lead with the numbers and rules they enforce: capacity, ID policy, cutoff time.","Map the physical layout: entrances, the spot where trouble starts.","Name the escalation chain — who decides, and on what channel."],"focus":["audience","structure"],"placeholder":"Capacity is 240, hard limit. ID everyone who looks under 30."},
    {"id":"audience-svc-mid-21","level":"mid","profession":"service","title":"The public review reply","scenario":"A one-star review says the reviewer waited 40 minutes and left. You know the context — a bus tour arrived unannounced — but your reply's real audience is the hundreds of future customers reading it, not the reviewer.","task":"Write a 3-4 sentence public reply written for the readers over the reviewer's shoulder.","tips":["Acknowledge specifically, without a courtroom defense.","Explain in one clause; over-explaining reads as excuse-making to onlookers.","Show future guests what you did about it — that's what they're scanning for."],"focus":["audience","impact"]},
    {"id":"audience-svc-mid-22","level":"mid","profession":"service","title":"Break rules, minus the legalese","scenario":"An audit found staff skipping legally required breaks, so you have to re-communicate the rules. The compliance sheet reads like statute. Your staff need to know: when their break is, that it's not optional, and what to do if the floor's slammed.","task":"Write the plain-language version in 3-4 sentences.","tips":["State the rule as behavior: 30 minutes before your 5th hour, every shift.","Kill the loophole in advance: slammed floor means tell the lead, not skip it.","Make clear this protects them and the store — not a new way to get in trouble."],"focus":["audience","clarity"]},
    {"id":"audience-svc-mid-23","level":"mid","profession":"service","title":"The second-keyholder case","scenario":"You want the owner to approve training a second keyholder. Your draft talks about how exhausted you are opening six days a week. Fair, but the owner decides on business risk: what happens to the store when you're sick, on vacation, or gone.","task":"Write a 3-4 sentence case framed in business-risk terms.","tips":["Lead with the store's exposure: one keyholder means one sick day closes the doors.","Quantify a late-open morning in lost sales.","Your workload is real — but present it as risk concentration, not fatigue."],"focus":["audience","impact"],"placeholder":"Right now if I'm sick, the store doesn't open."},
    {"id":"audience-svc-mid-24","level":"mid","profession":"service","title":"The card fee, said at the till","scenario":"The store is adding a 2% surcharge on card payments under $10. Cashiers need one sentence to say when a customer notices, because 'it's a processing-cost recovery policy' will start arguments at the register.","task":"Write the one-sentence script for cashiers, plus one sentence for the follow-up question.","tips":["Short, neutral, and non-defensive — cashiers repeat it fifty times a day.","Give the escape valve: cash or a $10 basket avoids it.","Script the second sentence too, for the customer who pushes back."],"focus":["audience","concision"]},
    {"id":"audience-svc-mid-25","level":"mid","profession":"service","title":"The uniform policy, from their side","scenario":"You're introducing a stricter uniform standard: plain black shirts, closed-toe shoes, name tags always. Your draft lists rules like a citation notice. Your staff's real questions: who pays for the shirts, what happens to warnings, why now.","task":"Write the announcement that answers the staff's actual questions in the first three sentences.","tips":["Answer 'who pays' immediately — it's the first thing everyone wonders.","Give the grace period and how enforcement starts.","One honest sentence on why now beats a paragraph of policy language."],"focus":["audience","clarity"]}
  ],
  "structure-that-carries": [
    {"id":"structure-svc-mid-01","level":"mid","profession":"service","title":"The opening checklist, in buckets","scenario":"Your opening checklist has grown to 22 items in random order: brew coffee, check the safe, unlock the patio, count the till, turn on the ovens, check yesterday's notes. New openers keep missing things because there's no shape to it.","task":"Group the checklist into three ordered buckets with a name for each.","tips":["Find the natural grouping: money, equipment, floor — or by physical route through the building.","Order the buckets by what must happen first.","Each bucket name should tell the opener what mode they're in."],"focus":["structure","clarity"],"placeholder":"Bucket 1 — Money and security: safe, till, alarm log."},
    {"id":"structure-svc-mid-02","level":"mid","profession":"service","title":"SCQA for the weekend staffing pitch","scenario":"You want the owner to move from a flat weekend schedule to a split-shift model that adds hands during the 6-9pm crush without adding total hours. You have the data; you don't have the story shaped yet.","task":"Write the pitch as four sentences: Situation, Complication, Question, Answer.","tips":["Situation: what's true now that the owner already agrees with.","Complication: what changed or what's breaking — the 6-9pm crush.","The Answer is your split-shift model, stated as the resolution, not a maybe."],"focus":["structure","impact"],"placeholder":"Weekends run on a flat schedule of six staff open to close. But between 6 and 9pm..."},
    {"id":"structure-svc-mid-03","level":"mid","profession":"service","title":"PREP: the happy-hour question","scenario":"Mid-conversation, the owner asks: 'Should we extend happy hour to weekends?' You have a view — no, it would cannibalize your best full-price hours — but out loud you tend to think in circles before landing anywhere.","task":"Answer aloud in PREP form: Point, Reason, Example, Point — under 30 seconds.","tips":["Point first: 'I wouldn't — here's why.'","One reason, one concrete example from your own numbers.","Restate the point in one closing line so the answer has edges."],"focus":["structure","clarity"]},
    {"id":"structure-svc-mid-04","level":"mid","profession":"service","title":"The incident report skeleton","scenario":"A fight broke out near the bar last Saturday and you have to write it up for the owner and possibly the insurer. Your draft is one long paragraph mixing what happened, what staff did, and what you think should change.","task":"Restructure the report into three labeled sections and write the first line of each.","tips":["Separate: what happened (facts only), what we did, what we recommend.","Facts section carries times and names; opinions live only in recommendations.","A reader should be able to cite section one in a legal context without your commentary tangled in."],"focus":["structure","precision"],"placeholder":"WHAT HAPPENED: At approximately 11:20pm..."},
    {"id":"structure-svc-mid-05","level":"mid","profession":"service","title":"The holiday schedule message","scenario":"You're announcing how December scheduling works: request deadlines, blackout dates, how conflicts get resolved, and the incentive for working Christmas Eve. Your draft mentions all four in a stream-of-consciousness paragraph people will misread.","task":"Rewrite as one governing line plus three or four clearly separated parts.","tips":["Governing line: the one sentence everything else hangs from.","One part per topic, visually separated — people screenshot these.","Put deadlines in the first part; nobody reads to the bottom in the group chat."],"focus":["structure","clarity"]},
    {"id":"structure-svc-mid-06","level":"mid","profession":"service","title":"The monthly report that carries itself","scenario":"Your monthly report to the district manager is a wall of numbers and anecdotes in the order you remembered them. The DM has asked twice for something 'easier to act on.'","task":"Design the report's structure: one headline sentence and three fixed sections, and write the headline for this month.","tips":["A recurring report should have the same skeleton every month — readers learn where to look.","Sections that work: results vs plan, problems needing you, decisions I've made.","The headline sentence states the month's single most important fact."],"focus":["structure","audience"],"placeholder":"Headline: labor overrun erased October's sales gain — plan below."},
    {"id":"structure-svc-mid-07","level":"mid","profession":"service","title":"Onboarding, week by week","scenario":"Your onboarding notes for new hires are a pile of 30 things to eventually cover: till procedures, the menu, closing duties, the dress code, who's who. New people get whatever the trainer remembers that day.","task":"Organize the pile into a first-shift / first-week / first-month structure with 2-3 items named per stage.","tips":["Sort by when the knowledge is needed, not by topic.","First shift = what keeps them safe and functional today.","Cap each stage — a structure that holds everything holds nothing."],"focus":["structure","audience"]},
    {"id":"structure-svc-mid-08","level":"mid","profession":"service","title":"The complaint reply with bones","scenario":"A customer emailed a long complaint about a ruined anniversary dinner: slow service, a wrong dish, a distracted server. Your reply draft responds to each point in the order she raised them, which reads as line-by-line litigation.","task":"Restructure the reply: one governing message, then at most three parts.","tips":["Governing message first: we got this wrong and here's what we're doing.","Group her points rather than answering seriatim — three complaints, one failure.","End with the concrete make-good and a direct way to reach you."],"focus":["structure","audience"],"placeholder":"You're right — we let you down on a night that mattered."},
    {"id":"structure-svc-mid-09","level":"mid","profession":"service","title":"The maintenance request that gets scheduled","scenario":"Your emails to the maintenance contractor ramble, and your requests keep landing at the bottom of his queue. A request he can schedule needs three things: what's broken, what it's costing, and when you need someone.","task":"Write a maintenance request in exactly three sentences — issue, impact, ask.","tips":["One sentence each; resist the urge to elaborate.","Impact in operational terms: what you can't serve, what safety risk is live.","The ask includes a date and your availability window."],"focus":["structure","concision"],"placeholder":"The ice machine is producing about half volume. On an 80-degree Saturday that means..."},
    {"id":"structure-svc-mid-10","level":"mid","profession":"service","title":"One idea for the standards meeting","scenario":"You're calling a rare all-staff meeting because standards have slipped: sloppy uniforms, late openings, phones on the floor. Your notes list eleven grievances. Eleven complaints produce an audience that hears nagging, not a message.","task":"Write the one governing idea for the meeting, then the three buckets everything falls under.","tips":["Find the sentence above the complaints: what do all eleven have in common?","Three buckets maximum — group ruthlessly.","Every specific you mention should visibly belong to a bucket."],"focus":["structure","impact"],"placeholder":"One idea for today: we've let 'almost right' become our standard."},
    {"id":"structure-svc-mid-11","level":"mid","profession":"service","title":"Sorting the comment-card pile","scenario":"You've got six weeks of customer feedback: 'music too loud,' 'server was amazing,' 'waited forever for the check,' 'love the new menu,' 'table was sticky,' and forty more. The owner asked what customers are saying. A raw list answers nothing.","task":"Group the feedback into three themes and write the one-line takeaway for each.","tips":["Themes are claims, not categories: 'speed of service is our biggest complaint' beats 'service comments.'","Count roughly — 'about half the complaints' gives a theme weight.","Flag the one theme that needs action versus the ones to just keep watching."],"focus":["structure","precision"]},
    {"id":"structure-svc-mid-12","level":"mid","profession":"service","title":"SCQA for the espresso machine","scenario":"The espresso machine is nine years old, breaks monthly, and each breakdown kills your highest-margin sales for a day. You want the owner to approve a $7,400 replacement, and you get one shot at the pitch over coffee on Thursday.","task":"Write the pitch in SCQA form, four to five sentences total.","tips":["Situation: the machine's role — espresso drinks are your margin engine.","Complication: the failure pattern and its cost per incident.","Answer with the number and the payback period, not just 'we need a new one.'"],"focus":["structure","impact"]},
    {"id":"structure-svc-mid-13","level":"mid","profession":"service","title":"PREP: why labor is up","scenario":"On a walkthrough, the district manager asks: 'Labor's at 31% — why?' You know the answer: two new hires in training and overtime from covering a resignation. Under the sudden spotlight you tend to list facts in random order.","task":"Answer aloud in PREP form in under 30 seconds.","tips":["Point: 'It's temporary, driven by two known causes.'","Reasons with numbers: training hours and the overtime bridge.","Close by naming when it normalizes — that's the reassurance the question is really seeking."],"focus":["structure","precision"],"placeholder":"It's a temporary spike with two known causes."},
    {"id":"structure-svc-mid-14","level":"mid","profession":"service","title":"The safety briefing in three buckets","scenario":"Your quarterly health-and-safety briefing has become a 20-minute list nobody retains: wet floor signs, knife handling, allergen protocol, fire exits, the first-aid kit, chemical storage, lifting technique. It needs a shape people can remember at 7pm on a slammed Friday.","task":"Reorganize the briefing under three memorable buckets and name what goes in each.","tips":["Buckets people can recall under stress: e.g., protect the guest, protect yourself, protect the building.","Every item must land in exactly one bucket.","Close the briefing by naming the three buckets again — the structure IS the takeaway."],"focus":["structure","audience"]},
    {"id":"structure-svc-mid-15","level":"mid","profession":"service","title":"The hiring proposal","scenario":"You want to add a part-time dishwasher-prep hybrid role. Your draft to the owner mixes the job duties, the schedule gap it fills, the cost, and two candidate leads into one breathless paragraph.","task":"Restructure the proposal: recommendation first, then three supporting sections.","tips":["Line one is the ask: role, hours, cost per week.","Sections: the gap it fills, the math, the plan to fill it.","The owner should be able to say yes after the first section and skim the rest."],"focus":["structure","clarity"],"placeholder":"I want to add a 20-hour dish-prep role at about $340/week. Here's the case."},
    {"id":"structure-svc-mid-16","level":"mid","profession":"service","title":"The vacation handover doc","scenario":"You're taking your first real vacation in two years, and the assistant lead is covering. Your handover draft is a brain dump: supplier quirks, the tricky regular, payroll deadlines, what to do if the alarm trips — in no usable order.","task":"Structure the handover into sections ordered by how urgently she'd need each one.","tips":["Order by urgency of lookup: emergencies first, weekly rhythms second, background color last.","Emergencies section: symptom → action → phone number, one line each.","Test it: could she find the alarm procedure in ten seconds at 6am?"],"focus":["structure","audience"]},
    {"id":"structure-svc-mid-17","level":"mid","profession":"service","title":"The supplier comparison","scenario":"You've gathered quotes from three produce suppliers and the owner wants your take. Your draft describes each supplier in turn — history, pricing, delivery terms — leaving the owner to do the comparing.","task":"Restructure: your recommendation first, then a comparison organized by the two or three factors that actually decide it.","tips":["Organize by decision factor (price, reliability, delivery window), not by supplier.","Lead with your pick and the single strongest reason.","Two suppliers can share a row; the structure should make the winner obvious."],"focus":["structure","clarity"]},
    {"id":"structure-svc-mid-18","level":"mid","profession":"service","title":"Event night, by owner","scenario":"Saturday's 200-person private event has a 30-item to-do list in one long thread. Nothing has an owner, so everything is implicitly yours. You have a door person, a bar lead, a kitchen lead, and yourself.","task":"Reorganize the list into four owner-based buckets and write the one-line mission for each owner.","tips":["Group by who acts, not by topic — a list is only real when each line has a name.","Give each owner a mission sentence, not just tasks: 'Door: nobody waits more than two minutes.'","Keep a 'me only' bucket honest and short."],"focus":["structure","clarity"],"placeholder":"Bar (Jess): stocked and staffed for 200 by 5pm — full list below."},
    {"id":"structure-svc-mid-19","level":"mid","profession":"service","title":"The write-up that holds up","scenario":"You're documenting a formal warning for a server who has been rude to coworkers twice this month. If this ever supports a termination, it has to be structured: incidents with dates, the standard violated, what was communicated, consequences of recurrence.","task":"Write the skeleton of the write-up with those four sections, and complete the first one.","tips":["Incidents: dated, factual, observable — 'raised her voice at K. in front of guests,' not 'was disrespectful.'","Name the specific standard or policy, not a vibe.","The consequences section is a commitment — write only what you'll actually enforce."],"focus":["structure","precision"]},
    {"id":"structure-svc-mid-20","level":"mid","profession":"service","title":"The quarter, in one idea","scenario":"You're preparing a quarterly sit-down with the owner. The quarter had everything: a great July, a kitchen flood, two hires, one termination, a menu change that worked. Your notes are a timeline. Timelines don't make points.","task":"Write the one governing sentence for the quarter, then the three points that support it.","tips":["Force the verdict: was the quarter good, bad, or turning? The governing line says which.","Each supporting point gets one number.","Anything that doesn't support the governing idea goes in an appendix or gets cut."],"focus":["structure","impact"],"placeholder":"The quarter's story: we absorbed two bad breaks and still grew — because of two changes worth keeping."},
    {"id":"structure-svc-mid-21","level":"mid","profession":"service","title":"The refund-thread cleanup","scenario":"A confusing group-chat thread about when staff can offer refunds versus store credit has produced three contradictory answers from three shift leads. You're writing the message that settles it.","task":"Write the settling message: one rule up top, then the two or three cases underneath.","tips":["State the governing rule in line one — the sentence people will quote later.","Cases ordered by frequency: the everyday one first, the rare one last.","Explicitly retire the wrong answers: 'this replaces what was said earlier.'"],"focus":["structure","clarity"]},
    {"id":"structure-svc-mid-22","level":"mid","profession":"service","title":"SCQA: closing an hour earlier","scenario":"Weeknight sales after 9pm average $85 against roughly $110 in labor and utilities to stay open. You want to propose closing at 9 instead of 10 on weekdays. The owner is sentimental about being 'the place that's always open.'","task":"Write the proposal in SCQA form, acknowledging the sentiment inside the Situation.","tips":["Fold the owner's identity into the Situation so they feel understood before the numbers land.","Complication: the last hour loses money every single weeknight.","The Answer can preserve the identity: keep Friday late, trim Monday-Thursday."],"focus":["structure","audience"],"placeholder":"Being open late has always been part of who we are — and most nights it works."},
    {"id":"structure-svc-mid-23","level":"mid","profession":"service","title":"The keyholder training plan","scenario":"You're training your strongest server to become a keyholder. Everything she needs to learn is in your head: alarm codes, the safe, closing counts, what to do when a vendor shows up unannounced, when to call you versus decide alone.","task":"Structure the training as three stages with a clear 'can now do X alone' gate for each.","tips":["Stage by trust level: shadow, supervised, solo.","Each gate is observable: 'closed three nights with me watching, zero count errors.'","The judgment calls (call me vs. decide) deserve their own explicit list — that's the real curriculum."],"focus":["structure","clarity"]},
    {"id":"structure-svc-mid-24","level":"mid","profession":"service","title":"PREP: the discounted booking","scenario":"An event planner wants your venue on a Saturday in peak season at 30% off, arguing exposure and future bookings. The owner asks what you think, right there in front of the planner. You need a structured answer, out loud, now.","task":"Answer in PREP form — Point, Reason, Example, Point — in a way you could say with the planner present.","tips":["Your point can be conditional and still be a point: 'Yes, at 15% — not 30.'","Reason with one number: what a peak Saturday grosses at full rate.","Keep it professional in front of the third party — firm on numbers, warm in tone."],"focus":["structure","impact"]},
    {"id":"structure-svc-mid-25","level":"mid","profession":"service","title":"Three causes of the stockouts","scenario":"You keep running out of things mid-shift: lemons Tuesday, to-go lids Thursday, the house red on Saturday. Each stockout has its own story, but the owner asked the bigger question: why does this keep happening?","task":"Group the recent stockouts into two or three root causes and write the one-line diagnosis for each.","tips":["Sort the incidents before you explain them: ordering error, usage spike, supplier miss?","Each cause gets its own fix — that's how you know the grouping is real.","Answer the owner's actual question: the pattern, not the anecdotes."],"focus":["structure","precision"],"placeholder":"The eight stockouts this month trace to three causes."}
  ],
  "cut-to-the-bone": [
    {"id":"concise-svc-mid-01","level":"mid","profession":"service","title":"The group-chat announcement, halved","scenario":"Your draft announcement runs 130 words: 'Hey everyone, hope you're all doing well! So as some of you may have heard, we're going to be making a few changes to how we handle closing duties, and I know change can be annoying, but I really think this will make things easier for everybody in the long run...' The actual change is two sentences.","task":"Cut the announcement to under 40 words without losing the change or the start date.","tips":["Delete the throat-clearing: the greeting, the 'as some of you may have heard.'","Keep the what and the when; the reassurance can be one clause.","Read it as a tired server on a break — every extra word costs you a reader."],"focus":["concision","clarity"],"placeholder":"New closing routine starts Monday:"},
    {"id":"concise-svc-mid-02","level":"mid","profession":"service","title":"The feedback message, de-hedged","scenario":"You're messaging a host about repeatedly seating large parties in the wrong section: 'I just wanted to maybe mention that it might be better if we could possibly try to keep the big parties in the back section when we can, if that makes sense?' Nothing in that sentence commits to anything.","task":"Rewrite the message with the hedges cut and the expectation clear.","tips":["Cut 'just,' 'maybe,' 'might,' 'possibly,' 'if that makes sense.'","State the expectation as the way things work: large parties go in the back section.","You can be warm and unhedged at the same time — warmth isn't vagueness."],"focus":["concision","impact"],"placeholder":"One adjustment: parties of 6+ go in the back section."},
    {"id":"concise-svc-mid-03","level":"mid","profession":"service","title":"The shift-change email diet","scenario":"Your email announcing new shift-change rules runs 300 words, restating each rule two ways and apologizing for the inconvenience three times. Staff will skim it, miss the deadline rule, and keep making late swaps.","task":"Cut the email to under 100 words with every rule stated exactly once.","tips":["Each rule appears once, as a bullet — restating 'in other words' doubles length, not clarity.","One apology maximum, if any.","The deadline rule goes first, since it's the one being broken."],"focus":["concision","structure"]},
    {"id":"concise-svc-mid-04","level":"mid","profession":"service","title":"The incident report, defatted","scenario":"Your incident report about a broken window opens: 'It should be noted that at approximately some time around 10pm or so, what appears to have possibly been an attempted break-in may have occurred at the rear entrance area of the premises.' Half those words are protective padding.","task":"Rewrite the sentence stating only what you actually observed, in half the words.","tips":["'It should be noted that' notes nothing — delete it.","One uncertainty marker per fact: 'around 10pm' OR 'approximately,' not both.","Say what you saw: the rear window was broken; the till was untouched."],"focus":["concision","precision"],"placeholder":"Around 10pm, someone broke the rear window."},
    {"id":"concise-svc-mid-05","level":"mid","profession":"service","title":"The ask without the shrink","scenario":"Your text to the owner: 'Sorry to bother you, I know you're super busy, but I was just wondering if maybe you'd had a chance to look at the schedule thing I sent over? No worries if not!' You need an answer today, and this message says the opposite.","task":"Rewrite the text so the ask is direct and time-bound, in one or two sentences.","tips":["Cut 'sorry to bother,' 'just wondering,' and 'no worries if not' — they invite delay.","Name the decision and the deadline.","Direct is respectful: it costs the reader less time than fluff does."],"focus":["concision","impact"],"placeholder":"Need your yes/no on the November schedule by tonight —"},
    {"id":"concise-svc-mid-06","level":"mid","profession":"service","title":"The five-minute huddle in ninety seconds","scenario":"Your pre-shift huddle notes cover the reservation list, a menu change, a reminder about side work, and a shout-out — scripted at five minutes. The kitchen needs everyone on the floor in two.","task":"Cut the huddle script to 90 seconds (about 120 words) without dropping any of the four topics.","tips":["One or two sentences per topic — a huddle is headlines, not stories.","The shout-out can be one sentence and still land.","Cut every 'as you guys know' and 'real quick' — say it or don't."],"focus":["concision","structure"]},
    {"id":"concise-svc-mid-07","level":"mid","profession":"service","title":"The supplier email, minus the wind-up","scenario":"Your email to a supplier starts: 'I hope this email finds you well. I just wanted to reach out and touch base regarding the delivery situation we discussed previously, as I wanted to circle back and see where things stand.' Forty words in, you haven't said anything.","task":"Rewrite the opening so the first sentence carries actual content.","tips":["'Reach out,' 'touch base,' 'circle back' are content-free — cut all three.","First sentence: the thing you need and by when.","Politeness lives in tone and a closing line, not in a padded opening."],"focus":["concision","clarity"],"placeholder":"Following up on the missed Thursday delivery: I need..."},
    {"id":"concise-svc-mid-08","level":"mid","profession":"service","title":"The redundant-pair purge","scenario":"Your new store policy doc is full of doubled phrases: 'each and every shift,' 'basic and fundamental standards,' 'null and void,' 'first and foremost,' 'any and all violations.' It reads like a lease, and your staff are nineteen.","task":"Rewrite three of those phrases as single words and one full policy sentence in plain language.","tips":["Every doubled pair: keep one word, cut the twin.","Legal-sounding pairs don't add enforceability to a store policy — just fog.","Read the sentence aloud; if you wouldn't say it to a person, rewrite it."],"focus":["concision","clarity"]},
    {"id":"concise-svc-mid-09","level":"mid","profession":"service","title":"The nominalization sweep","scenario":"Your report to the district manager says: 'We conducted an investigation into the discrepancy and made a determination that the implementation of additional verification procedures at delivery receiving would result in a reduction of losses.' Every verb has been buried in a noun.","task":"Rewrite the sentence with the verbs dug back out, in roughly half the words.","tips":["'Conducted an investigation' → investigated; 'made a determination' → decided.","Buried verbs hide who did what — dig them out and the sentence gets honest.","Aim for: we investigated, we found, we're changing X."],"focus":["concision","precision"],"placeholder":"We investigated the discrepancy and decided to..."},
    {"id":"concise-svc-mid-10","level":"mid","profession":"service","title":"The review reply, trimmed to three","scenario":"Your draft reply to a mixed online review runs nine sentences: thanks, apology, explanation, another apology, backstory about staffing, a promise, an invitation back, more thanks, and your name. Future customers reading it see rambling, not care.","task":"Cut the reply to three sentences that keep the acknowledgment, the fix, and the invitation.","tips":["One apology, specific to their complaint, beats three general ones.","Cut the staffing backstory — readers hear excuses.","Three sentences signal confidence; nine signal panic."],"focus":["concision","audience"]},
    {"id":"concise-svc-mid-11","level":"mid","profession":"service","title":"The apology cascade","scenario":"Your email to a customer whose catering order was wrong contains five apologies: 'so sorry,' 'sincerely apologize,' 'deeply regret,' 'sorry again for any inconvenience,' 'apologies once more.' The refund offer — the thing she actually wants — is in sentence seven.","task":"Rewrite with one strong apology and the remedy in the first two sentences.","tips":["One specific apology carries more weight than five reflexive ones.","Lead with the remedy — it's the sincerest apology you have.","'Any inconvenience' is generic; name what actually went wrong."],"focus":["concision","impact"],"placeholder":"We got your order wrong, and I'm sorry — here's what I'm doing about it."},
    {"id":"concise-svc-mid-12","level":"mid","profession":"service","title":"The closing checklist, one line each","scenario":"Your closing checklist explains each task in a paragraph: 'When wiping down the espresso machine, it's important to remember that the steam wand should be purged first because milk residue can build up...' Closers at 11pm need commands, not essays.","task":"Rewrite three checklist paragraphs as one-line commands.","tips":["Verb first: purge the steam wand, then wipe.","The why can live in the training doc — the checklist is for doing.","If a line needs a warning, make it three words in caps, not a clause."],"focus":["concision","clarity"],"placeholder":"1. Purge steam wand, then wipe machine."},
    {"id":"concise-svc-mid-13","level":"mid","profession":"service","title":"The job posting on a diet","scenario":"Your job ad for a line cook runs 400 words, half of it phrases like 'the ideal candidate will possess the ability to demonstrate a commitment to excellence in a fast-paced environment.' Good cooks skim past it to the pay, which you buried.","task":"Cut the posting to under 120 words with pay, hours, and the real job up front.","tips":["Pay and schedule in the first two lines — it's the first thing every applicant looks for.","'Fast-paced environment' says nothing; 'Friday nights run 200 covers' says everything.","Cut 'the ideal candidate will possess' — write 'you can...' and list three real skills."],"focus":["concision","audience"]},
    {"id":"concise-svc-mid-14","level":"mid","profession":"service","title":"The schedule post, minus the wind-up","scenario":"Every week you post the schedule with the same preamble: 'Hey team! Hope everyone had a great week! So here's the schedule for next week, let me know if there are any issues or conflicts or anything at all, happy to work things out as always!' The preamble is longer than most people's shifts entry.","task":"Write the schedule post in two sentences: where it is, and the deadline for flagging conflicts.","tips":["The schedule is routine — treat it routinely.","Keep the one operative rule: conflicts flagged by Thursday 5pm.","Friendliness can be two words; it doesn't need two sentences."],"focus":["concision","clarity"],"placeholder":"Next week's schedule is up. Flag conflicts by Thursday 5pm."},
    {"id":"concise-svc-mid-15","level":"mid","profession":"service","title":"The handover note, tightened","scenario":"Your shift handover note runs 200 words, most of it narrative: 'The afternoon started off pretty slow but then around 3 we got a rush which was fine, we handled it, then the delivery came which mostly went fine except...' The closer needs 30 seconds of facts.","task":"Cut the note to five lines of pure handover: open issues, counts, and anything unusual.","tips":["Cut everything that resolved itself — 'we handled it' means it doesn't go in the note.","One line per open item, verb-first.","The note's job: nothing surprises the closer that you already knew."],"focus":["concision","structure"]},
    {"id":"concise-svc-mid-16","level":"mid","profession":"service","title":"The price-increase notice, unhedged","scenario":"Your notice to regulars about a menu-price increase hedges everywhere: 'Due to a variety of factors, we may have to slightly adjust some of our pricing somewhat in the coming period.' Customers read weasel words as hiding something worse than the truth.","task":"Rewrite the notice in two plain sentences: what's changing, when, and one honest reason.","tips":["'May,' 'slightly,' 'somewhat,' 'a variety of factors' — cut all of it.","State the real number; vagueness invites worse guesses.","One honest reason (costs are up) reads better than a fog of factors."],"focus":["concision","clarity"],"placeholder":"On March 1, most menu prices go up about 5%."},
    {"id":"concise-svc-mid-17","level":"mid","profession":"service","title":"The maintenance email, halved","scenario":"Your email about the flickering dining-room lights runs 180 words including the history of the fixture, two theories about the wiring, and an aside about the last electrician. The contractor needs: what, where, how urgent, when can you let him in.","task":"Cut the email to under 60 words that answer those four things.","tips":["Your wiring theories aren't load-bearing — he'll diagnose it himself.","Access windows save a phone call: name two times he could come.","Urgency in operational terms: dining room unusable after dark."],"focus":["concision","precision"]},
    {"id":"concise-svc-mid-18","level":"mid","profession":"service","title":"The agenda that fits on a napkin","scenario":"Your agenda for the monthly staff meeting lists nine items with sub-points, timed to 90 minutes. Attendance is mandatory and morale about these meetings is already thin. Six of the items could be a group-chat message.","task":"Cut the agenda to the three items that need a room, and write the one-line purpose for each.","tips":["The test: does this item need discussion, or just announcement? Announcements go to the chat.","Each surviving item gets a purpose line: decide X, hear concerns on Y.","A 25-minute meeting that ends early buys goodwill you'll need later."],"focus":["concision","structure"],"placeholder":"Three items, 25 minutes: 1) Decide holiday rotation..."},
    {"id":"concise-svc-mid-19","level":"mid","profession":"service","title":"The training doc's first page","scenario":"Page one of your training manual is a 250-word welcome about the company's journey, values, and commitment to excellence. New hires need page one to answer: what do I do when I walk in, and who helps me.","task":"Replace the welcome page with under 80 words that orient a day-one hire.","tips":["Cut the company story to one sentence — or move it to the back.","Page one earns its place with immediately useful facts.","Names beat titles: 'ask Rosa' beats 'consult your designated trainer.'"],"focus":["concision","audience"]},
    {"id":"concise-svc-mid-20","level":"mid","profession":"service","title":"The nag, condensed","scenario":"Your third group-chat reminder about side work runs six sentences of escalating sighing: 'Guys, I really hate to keep bringing this up again, but once again the side work situation last night was not great, and I feel like we've talked about this...' Long nags train people to skim you.","task":"Rewrite the reminder as two sentences: the standard, and what happens next time it's missed.","tips":["Cut the exasperation — it reads as weakness, not authority.","State the standard once, plainly, as fact.","The consequence sentence does the work six sighs can't."],"focus":["concision","impact"],"placeholder":"Side work wasn't done last night. Going forward:"},
    {"id":"concise-svc-mid-21","level":"mid","profession":"service","title":"The event brief, compressed","scenario":"Your staff brief for Saturday's wedding reception runs two pages: the couple's story, the planner's preferences, the timeline, the menu, the special requests. Staff will read it standing up, ten minutes before doors.","task":"Compress the brief to ten lines that cover only what changes staff behavior.","tips":["The couple's story is lovely and cuttable; the no-photos rule is not.","Timeline as times and triggers: 7:15 toasts — bar pauses service.","Special requests get names: table 2 is nut-free, the groom's mother gets champagne first."],"focus":["concision","structure"]},
    {"id":"concise-svc-mid-22","level":"mid","profession":"service","title":"The owner update, weekly edition","scenario":"Your weekly update to the owner has crept up to 500 words because you're afraid leaving anything out looks like hiding something. The owner has started replying 'thanks' without reading — you can tell.","task":"Cut this week's update to under 100 words: numbers, one problem, one decision made, one thing needing them.","tips":["Completeness isn't the goal — signal is. Four sections, one line each if possible.","The 'needs you' item goes last and unmissable, or first.","If nothing needs them, say so in four words — that's the best sentence an owner reads."],"focus":["concision","structure"],"placeholder":"Week of the 14th: sales $31.2k (+4%). One problem:"},
    {"id":"concise-svc-mid-23","level":"mid","profession":"service","title":"The refund policy, once","scenario":"The refund section of your customer-facing policy says the same thing three ways: 'Refunds are available within 14 days. Customers may return items for a full refund up to two weeks after purchase. Any purchase can be refunded inside of a 14-day window.' Three sentences, one fact.","task":"Rewrite the section as one sentence, plus one sentence for the single real exception.","tips":["Repetition doesn't reinforce in policy text — it makes readers hunt for differences that don't exist.","One rule, one exception, stop.","Plain terms: '14 days with receipt' beats 'within a 14-day window from date of purchase.'"],"focus":["concision","precision"]},
    {"id":"concise-svc-mid-24","level":"mid","profession":"service","title":"The phone-policy message","scenario":"Your draft about phones on the floor is 150 words of preemptive defense: 'I know everyone has lives and sometimes things come up, and I completely understand that phones are important, and I'm not trying to be the bad guy here, but...' The policy is one sentence long.","task":"Write the policy message in three sentences or fewer, including the exception for emergencies.","tips":["Cut the 'I'm not the bad guy' framing — stating a reasonable rule doesn't need a defense.","Rule, exception, done.","The shorter the message, the more it reads like a norm instead of a plea."],"focus":["concision","impact"],"placeholder":"Phones stay in the back during service."},
    {"id":"concise-svc-mid-25","level":"mid","profession":"service","title":"The rejection note, kind and short","scenario":"Your draft telling an interviewee she didn't get the barista job runs 200 words of cushioning: how strong the field was, how hard the decision was, how much you enjoyed meeting her. Buried in the middle: the actual no.","task":"Cut the note to three or four sentences that are kind, clear, and final.","tips":["The kindest structure: thanks, the decision, one true positive, the door if it's real.","Don't imply a future opening unless you mean it.","Cushioning that delays the point isn't kindness — it's discomfort management, yours."],"focus":["concision","audience"],"placeholder":"Thank you for interviewing with us — we've offered the role to another candidate."}
  ],
  "precision-and-evidence": [
    {"id":"precision-svc-mid-01","level":"mid","profession":"service","title":"'Slammed' in covers","scenario":"Your Saturday recap to the owner says the night was 'absolutely slammed, probably one of the busiest we've ever had.' The owner, deciding whether to add weekend staff, asks: busiest by how much? You have the POS numbers; your message just didn't use them.","task":"Rewrite the recap sentence with covers, sales, and a comparison the owner can act on.","tips":["Replace 'slammed' with the count: 212 covers, $9,400 in sales.","Give the baseline — versus an average Saturday or the record.","A staffing decision needs a number, not an adjective."],"focus":["precision","clarity"],"placeholder":"Saturday ran 212 covers, $9.4k — 18% over our Saturday average."},
    {"id":"precision-svc-mid-02","level":"mid","profession":"service","title":"The wait-time claim, skeptic-proofed","scenario":"You tell the district manager 'wait times have really improved since we changed the seating flow.' A skeptic would ask: improved from what, to what, measured how, over how long? Right now your claim answers none of that.","task":"Rewrite the claim so it survives a skeptical reading, with baseline, current figure, and window.","tips":["State before and after: 22 minutes average in May, 14 in June.","Say how you measured — ticket stamps, the host log.","Two data points is a start; four weeks is a trend. Say which you have."],"focus":["precision","impact"],"placeholder":"Average wait at peak dropped from 22 minutes to 14 over the four weeks since the change, per the host log."},
    {"id":"precision-svc-mid-03","level":"mid","profession":"service","title":"Date the patio opening","scenario":"You've been telling staff and regulars the patio reopens 'soon, probably in a few weeks once the furniture arrives and we get the railing sorted.' The owner wants to plan a promotion around it and needs an actual date.","task":"Rewrite the update committing to a date, or to a dated decision point.","tips":["'A few weeks' becomes a real date — or the date you'll know one.","Name the blocking item and when it resolves: railing inspection Tuesday.","People can plan around a date; nobody can plan around 'soon.'"],"focus":["precision","clarity"],"placeholder":"Patio opens Friday June 14; the railing passes inspection Tuesday and furniture lands Wednesday."},
    {"id":"precision-svc-mid-04","level":"mid","profession":"service","title":"Food cost, with the driver named","scenario":"Your note to the owner says food cost is 'creeping up a bit lately, mostly because prices are crazy right now.' That's two vague claims in one sentence. The POS and invoices can tell you the number and the actual driver.","task":"Rewrite with the percentage move, the window, and the one line item driving it.","tips":["'Creeping up' becomes 31% to 33.5% over eight weeks.","'Prices are crazy' becomes the item: beef up 22%, everything else flat.","Naming the driver points at the fix — respec the dish or reprice it."],"focus":["precision","impact"],"placeholder":"Food cost went from 31% to 33.5% in eight weeks — almost all of it is beef, up 22% since April."},
    {"id":"precision-svc-mid-05","level":"mid","profession":"service","title":"The review summary that means something","scenario":"Asked how online reviews are going, you reply 'mostly good, a few grumpy ones, nothing major.' The owner is deciding whether the new menu worked and needs the actual signal: average score, volume, and direction.","task":"Rewrite the summary in one or two sentences with the numbers and the trend.","tips":["'Mostly good' becomes 4.3 average across 31 reviews this month.","Trend beats snapshot: up from 3.9 the month before the menu change.","If the grumpy ones share a theme, name it in four words."],"focus":["precision","concision"],"placeholder":"4.3 average across 31 reviews this month, up from 3.9 — the complaints that remain are all about weekend waits."},
    {"id":"precision-svc-mid-06","level":"mid","profession":"service","title":"Forty comment cards, one insight","scenario":"You're presenting six weeks of comment cards to the owner and your draft is a list of every remark, good and bad, in the order collected. The owner will stare at it waiting for you to say what it means.","task":"Write the single insight sentence the pile supports, so the cards become evidence instead of noise.","tips":["Find the one claim the data actually makes — count the themes first.","Lead with the insight; the cards become the supporting exhibit.","If you can't state the takeaway in one sentence, keep sorting."],"focus":["precision","structure"],"placeholder":"The cards say one thing loudly: guests love the food and are irritated by the wait for the bill — 14 of 19 complaints."},
    {"id":"precision-svc-mid-07","level":"mid","profession":"service","title":"'Always late' becomes dates","scenario":"You're writing up a host for lateness and your draft says he's 'constantly late and it's become a real pattern lately.' If this document ever matters — to HR, to a dispute — 'constantly' is worthless. Your clock-in records are not.","task":"Rewrite the lateness claim as dated, checkable instances.","tips":["'Constantly' becomes: late 6 of his last 10 shifts, by 10 to 25 minutes.","Cite the source — the clock-in log, with dates.","Precision protects you both: he can't dispute it, and you can't be accused of exaggerating."],"focus":["precision","clarity"],"placeholder":"Clock-in records show late arrivals on 6 of your last 10 shifts: May 2 (14 min), May 5 (25 min)..."},
    {"id":"precision-svc-mid-08","level":"mid","profession":"service","title":"Proof the checklist works","scenario":"You rolled out a new room-cleaning checklist three weeks ago, and your update to the hotel GM says it's 'working really well, the team likes it.' The GM approved the trial on the promise it would speed rooms up — that's the claim to prove.","task":"Rewrite the update with the before/after numbers the trial was meant to move.","tips":["The claim that matters: rooms per shift, before and after.","Add the quality check — reinspection failures, guest complaints.","'The team likes it' is real but secondary; one sentence at the end."],"focus":["precision","impact"],"placeholder":"Three weeks in: 14.1 rooms per housekeeper per shift, up from 12.6, with reinspection failures down from 5 a week to 2."},
    {"id":"precision-svc-mid-09","level":"mid","profession":"service","title":"The bread waste, priced","scenario":"You keep telling the kitchen 'we're wasting a lot of bread' and nothing changes. The waste log says exactly how much: loaves baked, loaves tossed, per night. A vague complaint became background noise; a number might not.","task":"Write two sentences for the kitchen that turn the waste into units and dollars.","tips":["'A lot' becomes: 9 loaves a night, about $340 a month.","Translate to something felt — that's a shift's wages every month in the bin.","End with the specific change: bake to the par, not past it."],"focus":["precision","impact"],"placeholder":"We're tossing 9 loaves a night — about $340 a month, a full shift's wages in the bin."},
    {"id":"precision-svc-mid-10","level":"mid","profession":"service","title":"The big party, pinned down","scenario":"You told the kitchen 'we've got a big party coming Saturday, so be ready.' The chef needs numbers to prep: headcount, arrival time, set menu or open, allergies, kids. 'Big' and 'be ready' prep nothing.","task":"Rewrite the kitchen note with every figure the chef needs to plan prep.","tips":["Headcount, time, and menu format are the minimum three.","Allergies and kids' meals change prep — say them now, not Saturday.","Write it so the chef never has to ask a follow-up."],"focus":["precision","audience"],"placeholder":"Saturday party: 34 guests at 6:30pm, set menu B, two nut allergies confirmed, three kids' meals."},
    {"id":"precision-svc-mid-11","level":"mid","profession":"service","title":"Overtime, in hours and dollars","scenario":"Your message to the owner says the team has been 'doing a ton of overtime lately to cover everything.' The owner reads that as either a cost problem or a staffing case — but can't tell which, or how big, without numbers.","task":"Rewrite with the overtime hours, the cost, and the comparison to normal.","tips":["'A ton' becomes 41 overtime hours in two weeks, about $1,150.","Give the baseline: normal is under 10.","Then say what it means — this is the cost of not filling the open role."],"focus":["precision","clarity"],"placeholder":"We ran 41 overtime hours in the last two weeks (about $1,150) versus our usual 8-10 — that's the unfilled cook role."},
    {"id":"precision-svc-mid-12","level":"mid","profession":"service","title":"The dessert push, measured","scenario":"You asked servers to offer dessert on every table and told the owner it's 'definitely working.' The POS can say precisely: dessert attach rate before, attach rate now, dollars added. 'Definitely working' invites the question you should have answered.","task":"Rewrite the claim with the attach rate change and the revenue impact.","tips":["'Working' becomes: attach rate 11% to 19% in three weeks.","Multiply it out — about $480 a week in added sales.","Credit the behavior, not luck: the scripted offer is doing this."],"focus":["precision","impact"],"placeholder":"Dessert attach rate went from 11% to 19% since we started the table offer — roughly $480 a week."},
    {"id":"precision-svc-mid-13","level":"mid","profession":"service","title":"The late deliveries, counted","scenario":"You're escalating a delivery problem to the supplier's account manager, and your draft says trucks have been 'consistently late recently and it's causing real problems.' They'll politely ask for details — give them upfront instead.","task":"Rewrite the complaint as counted, dated instances with the operational cost.","tips":["'Consistently late' becomes: 5 of the last 8 deliveries past window, dates listed.","The cost in their terms: two prep shifts started an hour behind.","End with the specific fix: confirmed 7-9am window, or a call by noon prior."],"focus":["precision","structure"],"placeholder":"Five of our last eight deliveries arrived past the window (May 3, 7, 10, 14, 17) —"},
    {"id":"precision-svc-mid-14","level":"mid","profession":"service","title":"'She's doing better' — show it","scenario":"Asked about a cashier you've been coaching, you tell the owner she's 'doing a lot better.' Better at what, by how much? You track till variance and transaction speed — the improvement lives in those numbers, not the adjective.","task":"Rewrite the verdict with one or two measured improvements.","tips":["Pick the metrics the coaching targeted: till variance, speed, refund errors.","Give before and after: three till discrepancies in April, zero since.","One measured claim outweighs three warm impressions."],"focus":["precision","clarity"],"placeholder":"Real progress: three till discrepancies in April, zero in the five weeks since —"},
    {"id":"precision-svc-mid-15","level":"mid","profession":"service","title":"The walkthrough sales question","scenario":"The district manager is walking your floor and asks, casually, 'How are sales tracking this month?' The vague answer — 'pretty solid, I think we're up' — invites doubt. You looked at the dashboard this morning; say what it said.","task":"Answer aloud in two sentences with the actual numbers and one caveat if honest.","tips":["Give the figure and comparison: up 6% on last October, tracking $4k over plan.","One caveat calibrates you: the holiday weekend is doing some of that lifting.","Knowing your numbers cold IS the impression that matters on a walkthrough."],"focus":["precision","concision"]},
    {"id":"precision-svc-mid-16","level":"mid","profession":"service","title":"The temperature log that holds up","scenario":"Your cooks have been filling the fridge temperature log with checkmarks and 'OK.' If the inspector comes — or if someone gets sick — 'OK' is not a record. You're writing the note that resets the standard for what an entry looks like.","task":"Write a short team note that defines a proper log entry, with an example line.","tips":["An entry is a number, a time, and initials — show one done right.","Explain what the record is for: it's your defense on a bad day.","Name what happens to out-of-range readings: the action taken gets logged too."],"focus":["precision","clarity"],"placeholder":"From today, every fridge check is a number, not a checkmark. Like this: 'Walk-in 3.2°C, 2:15pm, JR.'"},
    {"id":"precision-svc-mid-17","level":"mid","profession":"service","title":"'Seemed off' won't do","scenario":"You lead a care team, and a support worker's shift note says a resident 'seemed a bit off today.' The nurse reading it at handover can do nothing with 'off.' What the worker actually saw: ate half her lunch, declined her walk, quieter than usual.","task":"Rewrite the note as the observable specifics a nurse can act on.","tips":["Replace the impression with what you'd testify to: ate half, declined the 2pm walk.","Compare to her normal — that's what makes it signal.","Keep interpretation out; flag it for assessment, don't diagnose."],"focus":["precision","audience"],"placeholder":"Mrs. Halloran ate about half her lunch (normally finishes), declined her 2pm walk, and spoke less than usual —"},
    {"id":"precision-svc-mid-18","level":"mid","profession":"service","title":"The promo, in redemptions","scenario":"The two-week coupon promo just ended and your summary for head office says it 'brought in tons of new people and created great buzz.' Head office is deciding whether to run it chain-wide. Buzz doesn't travel; numbers do.","task":"Rewrite the summary with redemptions, sales lift, and the one number that decides the rerun.","tips":["'Tons of people' becomes 214 redemptions, 61% from new customers.","Lift against the prior two weeks, stated as a percentage.","Include the cost side — discount given versus revenue added — that's the deciding ratio."],"focus":["precision","impact"],"placeholder":"The promo drove 214 redemptions (61% new customers) and lifted sales 9% over the prior two weeks, at a discount cost of $640."},
    {"id":"precision-svc-mid-19","level":"mid","profession":"service","title":"The catering quote, itemized","scenario":"A corporate client asked what a 40-person lunch would cost and you replied 'probably somewhere around a few hundred, depending on what you want.' She can't take 'somewhere around' to her boss. She needs a figure with edges.","task":"Write a short quote email with a per-head price, what it includes, and what moves it.","tips":["Anchor on a number: $16.50 a head for the standard spread, so about $660.","List what's in it — vagueness about inclusions is where disputes start.","Name the two variables that change the price, with their costs."],"focus":["precision","structure"],"placeholder":"For 40 people: $16.50/head ($660) for the sandwich-and-salad spread, including delivery and setup. Two add-ons change it:"},
    {"id":"precision-svc-mid-20","level":"mid","profession":"service","title":"The staffing gap, sized","scenario":"Your case to the owner for another hire says the team is 'really stretched thin and it's starting to show.' The owner approves numbers, not feelings. The roster says exactly how thin: open shifts, overtime, and the two Fridays you ran a section closed.","task":"Rewrite the case with the gap in shifts, hours, and consequences.","tips":["'Stretched thin' becomes: 11 uncovered shifts last month, 30 overtime hours.","The consequence that stings: a closed section on two Fridays is lost revenue, estimate it.","End with the ask sized to the gap: 24 hires-worth of hours a week."],"focus":["precision","impact"],"placeholder":"Last month we had 11 uncovered shifts and ran a section closed on two Fridays — roughly $1,800 in seats we couldn't serve."},
    {"id":"precision-svc-mid-21","level":"mid","profession":"service","title":"Glassware, counted","scenario":"You want the owner to approve sturdier (pricier) glassware, and your draft argument is 'we go through so much glassware it's ridiculous.' The bar log and invoices can turn 'so much' into a monthly figure that argues for itself.","task":"Write the two-sentence case with the breakage count, cost, and payback.","tips":["'So much' becomes 60-odd glasses a month, about $210.","Do the payback math on the sturdier line: costs 40% more, breaks a third as often.","The number makes the decision boring — which is what you want."],"focus":["precision","concision"],"placeholder":"We break about 60 glasses a month — $210. The toughened line costs 40% more per glass and would pay for itself in..."},
    {"id":"precision-svc-mid-22","level":"mid","profession":"service","title":"'Customers love it' — says who?","scenario":"After the store re-layout you told the DM 'customers love the new setup.' The DM, fairly, asks how you know. Compliments at the till are real but thin. What else could count as evidence — basket size, dwell time, sales by section?","task":"Rewrite the claim with the strongest evidence you could actually pull, and honestly label the anecdotal part.","tips":["Lead with the checkable: average basket up 7% since the change.","Label the soft evidence as soft: 'anecdotally, front-of-store comments are positive.'","Mixing labeled hard and soft evidence reads as honest; blending them reads as spin."],"focus":["precision","impact"],"placeholder":"Average basket is up 7% since the re-layout, and the new front table outsells the old endcap 2-to-1."},
    {"id":"precision-svc-mid-23","level":"mid","profession":"service","title":"'Almost done' isn't a status","scenario":"The owner asks how the storeroom renovation is going and your update says it's 'almost done, just a few things left.' Almost-done projects famously stay almost done for weeks. The honest status is a short list and a date.","task":"Rewrite the status as remaining tasks, who owns each, and the completion date.","tips":["'A few things' becomes the actual list: shelving anchors, the door lock, paint touch-up.","Each item gets an owner and a day.","The completion date is the status — everything else is detail."],"focus":["precision","clarity"],"placeholder":"Three items left: shelving anchors (contractor, Tue), door lock (locksmith, Wed), touch-up (us, Thu). Done Friday."},
    {"id":"precision-svc-mid-24","level":"mid","profession":"service","title":"One sentence over the sales table","scenario":"You're sending the owner the monthly POS export: sales by day, by category, by hour — hundreds of numbers. Without a takeaway, the spreadsheet is homework you've assigned your boss. Somewhere in the grid is one sentence worth saying.","task":"Write the single insight sentence you'd put above the table.","tips":["Find the claim the numbers actually support — not the biggest number, the biggest meaning.","Make it decision-shaped: 'weekday lunch is quietly becoming a third of revenue.'","The table below becomes evidence for your sentence, not a puzzle."],"focus":["precision","structure"],"placeholder":"The story in this month's numbers: weekday lunch now drives 31% of revenue, up from 22% in January."},
    {"id":"precision-svc-mid-25","level":"mid","profession":"service","title":"The theft pattern, checked","scenario":"You've told the owner 'most of the shoplifting happens in the evenings' and proposed moving the security guard's hours. It's a strong claim built on impressions. The incident log and camera timestamps could confirm it — or embarrass you.","task":"Write the version of the claim you'd send after checking, with the data and its limits.","tips":["Count the logged incidents by time band before you claim the pattern.","State the base: 9 of 13 logged incidents after 5pm — and admit the log misses some.","A checked claim with stated limits beats a confident guess every time."],"focus":["precision","impact"],"placeholder":"I pulled the incident log: 9 of 13 recorded thefts this quarter happened after 5pm —"}
  ],
  "executive-presence": [
    {"id":"presence-svc-mid-01","level":"mid","profession":"service","title":"Own the supplier pick","scenario":"The owner asked which of two coffee suppliers to sign with. Your draft lays both out neutrally — 'Roastery A is cheaper but slower to deliver; B costs more but never misses' — and hands the choice back. They asked you because you run the floor.","task":"Rewrite to lead with your recommendation and own it, with the options as support.","tips":["State your pick in sentence one — you have a view, so give it.","A neutral menu just pushes your job upward.","Name the trade-off, then say why your side of it wins here."],"focus":["impact","structure"],"placeholder":"I'd sign with B — a missed delivery costs us more than the price gap ever will."},
    {"id":"presence-svc-mid-02","level":"mid","profession":"service","title":"Signpost the owner meeting","scenario":"You have 30 minutes with the owner to cover the quarter, a staffing proposal, and a lease question. Your instinct is to dive into the first topic. A manager with presence frames the whole meeting first, so the owner knows the shape and where the decision points are.","task":"Write your 2-3 sentence opening that maps the meeting and states your bottom line up front.","tips":["Name the parts: three topics, one needs a decision today.","Give the headline now: the quarter was strong, staffing is my ask.","People relax and listen better when they know where you're going."],"focus":["structure","impact"],"placeholder":"Three things today: the quarter (good news), a staffing proposal I need a yes on, and a lease question to flag."},
    {"id":"presence-svc-mid-03","level":"mid","profession":"service","title":"The hiring call, unhedged","scenario":"After interviewing two candidates for assistant manager, your message to the owner reads: 'They both have strengths honestly, it kind of depends what we're looking for, I could see either working out.' You do have a preference — the message just refuses to say it.","task":"Rewrite to state your recommendation plainly with the one reason that decides it.","tips":["Make the call: hire Priya.","'Depends what we're looking for' is your job to answer, not ask.","One decisive reason beats a balanced non-answer."],"focus":["impact","clarity"],"placeholder":"Hire Priya. Both can run a shift, but she's the only one who handled the conflict question like a manager."},
    {"id":"presence-svc-mid-04","level":"mid","profession":"service","title":"Fact and judgment, untangled","scenario":"Reporting a dispute between two servers, your message to the owner reads: 'Jordan was completely out of line and clearly has an attitude problem, there was a whole scene at the pass.' Facts and your verdict are tangled — which lets a reader dismiss both.","task":"Rewrite separating what happened from what you make of it, clearly labeled.","tips":["Facts first, cleanly: raised voices at the pass at 8pm, guests noticed, Jordan walked out for ten minutes.","Then judgment, marked: 'my read is this is a pattern with Jordan.'","A reader can trust labeled judgment; blended judgment contaminates the facts."],"focus":["clarity","impact"],"placeholder":"What happened: at 8pm Jordan and Sam argued loudly at the pass and guests noticed. My read:"},
    {"id":"presence-svc-mid-05","level":"mid","profession":"service","title":"Steady after the kitchen fire","scenario":"A small flare-up on the line tonight triggered the suppression system. Everyone's safe, the kitchen is closed for cleanup, and you're calling the owner. You're shaken, and your instinct is to narrate the chaos in the order you experienced it.","task":"Script your first four sentences aloud: what happened, current state, next step, your recommendation.","tips":["Facts in steady order — panic in your voice becomes panic in theirs.","Current state plainly: everyone safe, kitchen closed, dining room fine.","End owning the next step, not asking what to do."],"focus":["impact","structure"]},
    {"id":"presence-svc-mid-06","level":"mid","profession":"service","title":"A position on delivery apps","scenario":"The owner asks whether the restaurant should join the delivery apps. Your honest first thought is 'it depends' — and it does, on margin, on the kitchen's capacity. But 'it depends' delivered flat is an abdication. Presence is taking a position inside the uncertainty.","task":"Write a 3-4 sentence answer that lands on a recommendation despite the genuine trade-offs.","tips":["Take a side: yes on one app, lunch only, as a 90-day test.","Name the condition that would change your mind — that's calibration, not hedging.","A bounded yes is a position; 'it depends' is a shrug."],"focus":["impact","clarity"],"placeholder":"My call: yes, but one app only and lunch only, as a 90-day test — here's the line I'd watch."},
    {"id":"presence-svc-mid-07","level":"mid","profession":"service","title":"The memo that finally decides","scenario":"Your memo about the underperforming brunch menu lists observations for three paragraphs — slow Sundays, high waste, mixed reviews — and ends with 'something to think about.' Every reader finishes it waiting for the sentence you never wrote.","task":"Write the missing sentence: your decision or recommendation, stated as the memo's opening line.","tips":["The observations all point somewhere — go there: cut brunch to Sundays only, relaunch in spring.","Put the decision first; the three paragraphs become your support.","'Something to think about' outsources the thinking. Do it yourself."],"focus":["impact","structure"],"placeholder":"Recommendation: cut brunch back to Sundays only from March, and revisit in June. Here's why."},
    {"id":"presence-svc-mid-08","level":"mid","profession":"service","title":"Calibrated on the holiday forecast","scenario":"The owner asks how December will go. Overclaiming ('it'll be huge') and underclaiming ('who knows, it's unpredictable') both cost you credibility. You know some things firmly — bookings, last year's pattern — and genuinely don't know others.","task":"Write a 3-4 sentence forecast that says what you're sure of, what you expect, and what you can't call.","tips":["Three levels: 'bookings are already 20% ahead' (fact), 'I expect our best December' (judgment), 'walk-in traffic I can't call' (unknown).","Confidence isn't certainty about everything — it's precision about your certainty.","End with what you're doing to cover the unknown."],"focus":["impact","precision"],"placeholder":"What I know: December bookings are already 20% ahead of last year. What I expect:"},
    {"id":"presence-svc-mid-09","level":"mid","profession":"service","title":"The POS rollout, with a spine","scenario":"On the area call, managers are asked for input on the new POS system rollout timing. Most will say 'whenever works for everyone.' You actually have a view — January would hit your quietest weeks and February wouldn't — and a reason for it.","task":"Script your 20-second contribution: position first, reason second.","tips":["Speak in position-reason order: 'January works for us — it's our quietest stretch.'","One reason, concrete, from your own operation.","Being the manager with a clear view is how area managers learn your name."],"focus":["impact","concision"]},
    {"id":"presence-svc-mid-10","level":"mid","profession":"service","title":"The event quote, owned","scenario":"A client asked whether to do their 50-person party as a buffet or plated service, and your reply lists pros and cons of each at length, ending with 'totally up to you!' She hired a venue partly to get a professional's judgment.","task":"Rewrite to recommend one format for her event, with the reasoning brief and the choice still hers.","tips":["Recommend: 'For 50 with speeches, I'd do plated — here's why.'","Keep it hers to overrule: a recommendation isn't a removal of choice.","Expertise offered plainly is the service she's paying for."],"focus":["impact","audience"],"placeholder":"For your group I'd recommend plated service — with speeches at 8, a buffet line fights the room."},
    {"id":"presence-svc-mid-11","level":"mid","profession":"service","title":"Opening the standards meeting","scenario":"You've called an all-staff meeting about slipping standards, and you're nervous enough that your drafted opening apologizes for the meeting twice before it says anything. The room will take its cue from your first three sentences.","task":"Write an opening that is calm, direct, and neither apologetic nor angry.","tips":["No apology for leading — 'sorry to drag everyone in' undercuts the next twenty minutes.","State why you're here in one plain sentence, without heat.","Signal the shape: what you'll cover, and that everyone leaves with clarity, not blame."],"focus":["impact","structure"],"placeholder":"Thanks for making time. We're here because our standards have slipped, I let it drift, and today we reset — three things."},
    {"id":"presence-svc-mid-12","level":"mid","profession":"service","title":"'I feel like maybe' surgery","scenario":"Your message to the owner reads: 'I feel like maybe we could kind of look at possibly changing up the weekend structure at some point, if that makes sense?' Somewhere under six hedges is an actual proposal about splitting the Saturday shift.","task":"Rewrite the sentence in the voice of someone who has decided.","tips":["Cut 'I feel like,' 'maybe,' 'kind of,' 'possibly,' 'at some point,' 'if that makes sense.'","What's left should assert: 'I want to split the Saturday shift starting next month.'","Decided doesn't mean closed — invite response after the position, not instead of it."],"focus":["impact","concision"],"placeholder":"I want to split the Saturday shift into two overlapping crews starting next month. Here's the case —"},
    {"id":"presence-svc-mid-13","level":"mid","profession":"service","title":"The debrief with a map","scenario":"The morning after a rough Saturday — long waits, two comped tables, a server in tears — you're debriefing the owner. Unstructured, this becomes a stew of anecdotes. Signposted, it becomes evidence you're in command of it.","task":"Write your opening two sentences: the frame, then the first signpost.","tips":["Frame it: 'Three things went wrong Saturday, one root cause, and I've made two changes.'","Then walk the structure you promised, in order.","The structure itself is the message: shaken managers ramble, steady ones number things."],"focus":["structure","impact"],"placeholder":"Saturday had three visible failures with one root cause — a hole in the mid-shift. Here's each, then the fix."},
    {"id":"presence-svc-mid-14","level":"mid","profession":"service","title":"The promise you shouldn't make","scenario":"After a guest found a hair in her food, your drafted reply promises it 'will never, ever happen again.' You can't guarantee that, and sophisticated readers know it — the overclaim reads as panic, not assurance. What you CAN promise is specific and real.","task":"Rewrite the assurance at a strength you can actually stand behind.","tips":["Swap the absolute for the concrete: what you changed, checked, or retrained this week.","'Here is exactly what we did about it' reassures more than 'never again.'","Calibrated language survives the second incident; absolute language doesn't."],"focus":["impact","precision"],"placeholder":"I can't promise perfection, but here's exactly what changed in our kitchen this week because of your visit:"},
    {"id":"presence-svc-mid-15","level":"mid","profession":"service","title":"The buyout recommendation","scenario":"A company wants to buy out the whole restaurant for a Tuesday night at a flat fee. It's good money against a slow night, but it bumps your regulars. The owner asks for your take, and your draft presents 'considerations on both sides.'","task":"Rewrite as a firm recommendation with the deciding math and the regulars handled.","tips":["Lead with your call: take it — a Tuesday grosses $1,900 and the buyout pays $3,200.","Address the cost you're accepting: regulars get a personal heads-up, not a locked door.","Both-sides analysis is the homework; the recommendation is the deliverable."],"focus":["impact","structure"],"placeholder":"Take the buyout. A normal Tuesday does $1,900; this pays $3,200 —"},
    {"id":"presence-svc-mid-16","level":"mid","profession":"service","title":"'My read' on the turnover","scenario":"Three staff have quit in two months and the owner asks why. You have facts (exit reasons, pay data) and a theory (the new closing structure is burning people out). Presence means offering the theory — labeled as yours — instead of hiding behind the facts.","task":"Write a 3-4 sentence answer: the facts, then your read, explicitly labeled.","tips":["Facts first: all three left within a month of the closing change; two cited hours.","Then: 'My read is the 1am closes are the driver.'","Offering a labeled interpretation is leadership; listing facts and shrugging is clerking."],"focus":["impact","clarity"],"placeholder":"The facts: all three quit within six weeks of the new closing structure, and two named the hours. My read:"},
    {"id":"presence-svc-mid-17","level":"mid","profession":"service","title":"The inspector at the door","scenario":"The health inspector just walked in mid-lunch-rush. Your team is watching how you react. The manager who flusters — over-explaining, hovering, apologizing in advance — sets a nervous tone the inspector notices too.","task":"Script your first three sentences: to the inspector, then to your team.","tips":["To the inspector: welcome, orient, offer access — brief and unbothered.","To the team, one steady line: 'Business as usual, keep serving.'","Calm is a decision you make out loud before you feel it."],"focus":["impact","audience"]},
    {"id":"presence-svc-mid-18","level":"mid","profession":"service","title":"Running the interview","scenario":"You're interviewing a candidate for the bar lead role — the first interview you've ever run from the hiring side. Opening with 'so, um, I guess tell me about yourself?' hands the room to the candidate. The interviewer sets the frame.","task":"Write your opening 3-4 sentences: the role, the plan for the hour, and the first real question.","tips":["Frame first: what the role is, what the conversation will cover, how long.","It relaxes strong candidates and structures weak ones — either way you learn more.","Your first question should chase evidence: 'walk me through a shift you ran that went sideways.'"],"focus":["structure","audience"],"placeholder":"Thanks for coming in. This is for the bar lead role — I'll spend ten minutes on the job, then most of our hour on your experience."},
    {"id":"presence-svc-mid-19","level":"mid","profession":"service","title":"The termination recommendation","scenario":"After three documented warnings, you believe a server needs to be let go. Your draft to the owner hints — 'I'm not sure how much longer we can keep going like this' — without saying the word. If you believe it, the message should say it.","task":"Rewrite to state the recommendation directly, with the record behind it in one sentence.","tips":["Say it: 'I'm recommending we terminate Alex's employment.'","One sentence of record: three documented warnings since June, no change.","Hinting forces the owner to say the hard word for you — that's not their job."],"focus":["impact","clarity"],"placeholder":"I'm recommending we let Alex go. Three documented warnings since June and the behavior hasn't changed."},
    {"id":"presence-svc-mid-20","level":"mid","profession":"service","title":"'What would you do?'","scenario":"You brought the owner a problem — a supplier dispute over a damaged shipment — and the owner turns it around: 'What would you do?' The reflex is to deflect back: 'well, it's really your call.' It's a test, and deflection fails it.","task":"Script your answer aloud: your call, your reason, and what you need from them.","tips":["Answer the actual question: 'I'd withhold payment on the damaged cases and keep the account.'","One reason with a number in it.","End with the narrow thing you need: 'I just need your OK to hold the payment.'"],"focus":["impact","concision"]},
    {"id":"presence-svc-mid-21","level":"mid","profession":"service","title":"The training session's spine","scenario":"You're running a 30-minute training on the new espresso machines. Your notes are a feature list. Sessions without a stated structure sag — people can't tell how much is left or what matters most.","task":"Write the opening that gives the session a spine: what, why, the three parts, and how it ends.","tips":["Tell them the shape: three parts, twenty minutes, then everyone pulls two shots.","Name what matters most up front: part two is the one that saves you mid-rush.","Ending with a doing-test beats ending with 'any questions?'"],"focus":["structure","audience"],"placeholder":"Thirty minutes, three parts: the daily routine, the mid-rush recovery moves, and what breaks it. Then you each pull two shots."},
    {"id":"presence-svc-mid-22","level":"mid","profession":"service","title":"Sunday hours: data, then a call","scenario":"The owner wonders aloud about closing Sundays. You pull the numbers: Sundays average $2,100 against $1,750 in costs — thin but positive, and it's when a third of your regulars come. The numbers alone don't decide it; someone has to.","task":"Write a 3-4 sentence response: the facts, then your position, clearly separated and clearly yours.","tips":["Facts without spin: Sundays net about $350 on the day.","Then the judgment, owned: 'I'd stay open — Sunday is where our regulars live.'","Separating the two lets the owner disagree with your call while trusting your numbers."],"focus":["impact","precision"],"placeholder":"The numbers: Sundays average $2,100 against $1,750 in costs — about $350 net. My call:"},
    {"id":"presence-svc-mid-23","level":"mid","profession":"service","title":"The group chat after a bad night","scenario":"Last night was a disaster — a double booking, two callouts, a shouting guest — and your drafted group-chat message radiates stress: 'Honestly I don't even know what to say about last night, that CANNOT happen again, we NEED to be better.' Heat without direction.","task":"Rewrite the message with calm authority: what happened, what changes, and one credit where due.","tips":["Drop the caps and the despair — the team needs a leader, not a mood.","Name the one concrete change that prevents the repeat.","Credit what held: whoever kept the floor moving deserves a line."],"focus":["impact","clarity"],"placeholder":"Rough night, and the double booking was the trigger. One change from today:"},
    {"id":"presence-svc-mid-24","level":"mid","profession":"service","title":"The renovation options, decided","scenario":"You've collected three contractor quotes for the bar renovation and your email to the owner presents them as a table with 'happy to discuss!' A table is homework. The owner wants your pick and your confidence level in it.","task":"Rewrite the email opening: your recommendation, the reason, and the runner-up in one line.","tips":["Lead with the pick: 'Go with Delgado — mid-price, and the only one who's done a working-bar reno.'","Confidence level is information: say if it's a strong or narrow call.","The table survives — below your recommendation, as evidence."],"focus":["impact","structure"],"placeholder":"My recommendation: Delgado Construction. Mid-price, and the only bid from a crew that's renovated a working bar."},
    {"id":"presence-svc-mid-25","level":"mid","profession":"service","title":"Bottom line for the area call","scenario":"You have four minutes on the monthly area video call to represent your location. Last time you narrated the month chronologically and got cut off before the important part. This time: bottom line first, three signposted points, done in three minutes.","task":"Script your opening 30 seconds: the bottom line and the map of your three points.","tips":["First sentence is the verdict: best month since opening, one risk to flag.","Signpost: 'Three things — the number, what drove it, and the risk.'","Finishing under time on a group call is presence everyone remembers."],"focus":["structure","concision"],"placeholder":"Bottom line: our best month since opening — sales up 11%. Three things: the number, what drove it, and one risk."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-svc-mid-01","level":"mid","profession":"service","title":"'Why are sales down?'","scenario":"The district manager opens the call with 'Sales are down 9% — why?' Your instinct is to start with context: the road construction, the weather, the competitor's opening. Context-first sounds like excuse-making. Answer-first sounds like command.","task":"Script your spoken answer: the direct answer in sentence one, support after.","tips":["First sentence answers the question: 'Two drivers — the road closure took our lunch walk-ins, and we lost our two best servers in the same month.'","Then one sentence of evidence for each.","End with what you're doing, unprompted — that's the question behind the question."],"focus":["clarity","structure"]},
    {"id":"pressure-svc-mid-02","level":"mid","profession":"service","title":"'Did you know about this?'","scenario":"A guest complaint reached the owner directly, and the owner asks point-blank: 'Did you know about this?' You did — you'd judged it handled. The tempting answers are a dodge ('well, sort of') or a dump (the whole story). The right answer is one word, then the context.","task":"Write your answer: the direct yes, then two sentences of what you knew and did.","tips":["'Yes' comes first — anything else sounds like the start of a cover story.","Then: what you knew, what you did, and why you didn't escalate.","If your judgment call was wrong, say that too. Owning it beats defending it."],"focus":["clarity","impact"],"placeholder":"Yes — it came to me Tuesday and I handled it directly with the guest. Here's what I did and where I misjudged:"},
    {"id":"pressure-svc-mid-03","level":"mid","profession":"service","title":"The 'I don't know' with a spine","scenario":"In a review of the numbers, the owner asks what percentage of your food cost is waste versus theft versus portioning. You don't know — the data isn't split that way. Bluffing is fatal; a bare 'I don't know' is weak. There's a third option.","task":"Write the answer that admits the gap and closes it: what you don't know, what you do, and when you'll have it.","tips":["Structure: 'I don't know the split. Here's what I do know. I'll have the answer by Friday.'","Offer the adjacent fact you DO have — total waste logged last month.","An 'I don't know' with a date attached builds more trust than a lucky guess."],"focus":["clarity","precision"],"placeholder":"I don't know the split today — the log doesn't separate them. What I can tell you now:"},
    {"id":"pressure-svc-mid-04","level":"mid","profession":"service","title":"'Who's responsible for this?'","scenario":"A furious guest whose reserved table was given away demands: 'Who's responsible for this?' Naming the host who made the error throws your staff to a stranger. Deflecting entirely sounds slippery. The answer is you — with the fix in the same breath.","task":"Script your spoken response: take the responsibility and pivot to the remedy in two sentences.","tips":["'I am — I run this floor' ends the hunt for a culprit instantly.","Pivot fast to what you're doing: the next table, the round on the house.","Never name the staff member; accountability flows up in public, down in private."],"focus":["impact","audience"]},
    {"id":"pressure-svc-mid-05","level":"mid","profession":"service","title":"Schedule pushback, no flinch","scenario":"You posted the holiday schedule and a veteran server challenges you in front of two others: 'This is ridiculous, I've worked every Christmas Eve for three years.' She's half right, and the room is watching whether you defend, fold, or hold.","task":"Write your response: acknowledge what's true, hold the decision, and name where the conversation continues.","tips":["Concede the true part plainly — 'you're right, you've carried Christmas Eve three years running.'","Hold the line without re-litigating in the group: the rotation stands this year.","Move the rest to private: 'come find me after close and I'll walk you through how I built it.'"],"focus":["impact","audience"],"placeholder":"You're right — three years running, and I weighed that. The rotation stands, and I'll walk you through why after close."},
    {"id":"pressure-svc-mid-06","level":"mid","profession":"service","title":"The loaded question","scenario":"After a mixed-up order, a customer asks, loudly: 'Is your staff even trained?' The question is bait — 'yes' sounds defensive, 'let me explain our training program' feeds the scene. Answer the real question underneath: will my order be right?","task":"Script the two-sentence response that defuses without taking the bait.","tips":["Skip the premise, answer the need: 'They are — and this one's on me to fix right now.'","Move to the concrete: what happens in the next five minutes.","The audience for your answer is every other table listening."],"focus":["audience","impact"]},
    {"id":"pressure-svc-mid-07","level":"mid","profession":"service","title":"The overtime challenge","scenario":"The owner scans payroll and asks sharply: 'Why am I paying $1,100 in overtime this month?' You know exactly why — two resignations you've told them about. Under the sharp tone, the instinct is to get defensive or re-argue the past. Just answer the number.","task":"Write the answer: the direct cause in one sentence, the trajectory in the second.","tips":["Answer the question asked: 'That's the cost of covering Dana and Marcus's shifts while we hire.'","Give the end date: overtime drops when the two new hires finish training on the 15th.","Skip the tone, answer the content — defensiveness escalates; facts close."],"focus":["clarity","precision"],"placeholder":"That's the cost of covering two open roles — Dana's and Marcus's shifts. It ends when the new hires finish training on the 15th."},
    {"id":"pressure-svc-mid-08","level":"mid","profession":"service","title":"The honest no on the target","scenario":"The owner asks: 'Will you hit the labor target this month?' You won't — you're tracking 31% against a 28% target, and the math can't close in two weeks. The tempting answer is 'we're working really hard on it.' The useful answer is no, with the number and the plan.","task":"Write the answer that says no cleanly and keeps your credibility.","tips":["Say it: 'No — we'll land around 30.5%.'","Explain in one sentence, without pleading: training hours for the two new hires.","Then next month's honest number. A precise no beats an optimistic maybe."],"focus":["clarity","impact"],"placeholder":"No. We'll land around 30.5% against the 28 target — the training hours don't wash out until next month."},
    {"id":"pressure-svc-mid-09","level":"mid","profession":"service","title":"Two questions at once","scenario":"On a tense call, the DM fires a double-barrel: 'What happened with the health inspection follow-up, and where are you on the manager-trainee thing?' Rattled people answer whichever fragment they heard last, and the first question comes back harder.","task":"Script your answer: name that there are two, answer them in order, one sentence of headline each.","tips":["Split them out loud: 'Two things there. Inspection first —'","Headline each answer before any detail.","Naming the structure buys you two seconds to think and sounds composed doing it."],"focus":["structure","clarity"]},
    {"id":"pressure-svc-mid-10","level":"mid","profession":"service","title":"The number you don't have","scenario":"Mid-walkthrough, the DM asks your current shrink percentage. You know last quarter's (2.1%) but not this month's — the count is Thursday. Guessing a number you might have to retract is worse than the honest bracket.","task":"Write the spoken answer: the number you have, the one you don't, and when you will.","tips":["Give the adjacent fact with its label: 'Last quarter closed at 2.1%.'","Name the gap without squirming: this month's count runs Thursday.","Offer the delivery: 'I'll text you the number Thursday night.' Then do it."],"focus":["precision","clarity"],"placeholder":"Last quarter closed at 2.1%. This month's count runs Thursday — I'll send you the number that night."},
    {"id":"pressure-svc-mid-11","level":"mid","profession":"service","title":"'Would YOU eat here?'","scenario":"A guest who just watched her order go wrong twice asks, half-laughing but not really: 'Honestly — would you even eat here?' A scripted 'of course!' sounds hollow. Honesty plus specifics is the only answer that lands.","task":"Script a response that is honest, specific, and turns the moment.","tips":["Yes needs evidence: what you actually order, why tonight isn't the norm.","Acknowledge what she watched — pretending it didn't happen kills the answer.","End in action: her meal remade, your eyes on it personally."],"focus":["audience","impact"]},
    {"id":"pressure-svc-mid-12","level":"mid","profession":"service","title":"The insurer on the line","scenario":"The insurance adjuster calls about last week's slip-and-fall and asks rapid, precise questions. The pressure instinct is to narrate everything you know, including theories and staff opinions. On this call, extra words are liabilities.","task":"Write your answers to 'what happened' in three sentences: facts you observed, nothing more.","tips":["Answer exactly what's asked, then stop — silence is allowed.","Facts you'd stand behind: times, actions taken, what the guest said and declined.","No theories, no 'probably,' no characterizing anyone. Offer the written incident report."],"focus":["precision","concision"],"placeholder":"At 8:40pm the guest slipped near the bar. Staff reached her within seconds; she declined medical attention. The incident report has the full timeline."},
    {"id":"pressure-svc-mid-13","level":"mid","profession":"service","title":"The reporter's call","scenario":"A guest's angry post about your restaurant went semi-viral, and a local reporter calls for comment while you're mid-shift. Anything you say may be quoted. 'No comment' reads as guilt; a rambling defense reads worse.","task":"Write the two-sentence statement you'd give: calm, factual, and closed-ended.","tips":["One sentence of position: we've spoken with the guest directly and addressed it.","No relitigating details — a quote war has no winner.","Close the door politely: further questions to the owner, then get off the phone."],"focus":["audience","concision"],"placeholder":"We take this seriously and we've been in direct contact with the guest to make it right. For anything further, I'll connect you with the owner."},
    {"id":"pressure-svc-mid-14","level":"mid","profession":"service","title":"'Give me one reason'","scenario":"You've asked for a second dishwasher on weekend nights and the owner, skeptical, says: 'Give me one reason this isn't just throwing money at the problem.' One reason. Not five. The discipline of the single best argument, under the gun.","task":"Write the one-sentence answer, then one sentence of evidence.","tips":["Pick your strongest card and play only it: table turns stall when the dish pit backs up.","Attach the number: Saturday's 20-minute plate shortage cost roughly two full turns.","Resisting the urge to pile on reasons is what makes the one reason land."],"focus":["impact","concision"],"placeholder":"Because the dish pit is the bottleneck, not the floor — Saturday we stopped seating for 20 minutes because there were no clean plates."},
    {"id":"pressure-svc-mid-15","level":"mid","profession":"service","title":"Challenged in the huddle","scenario":"Mid-huddle, as you explain the new section rotation, a server cuts in: 'This makes no sense, the old way was fine.' Six people watch you react. Squashing him looks brittle; caving looks weak; a genuine beat of engagement looks like leadership.","task":"Script your spoken response: take the objection seriously, answer it, and keep the huddle moving.","tips":["Repeat his point fairly first — it defuses the challenge better than volume.","One-sentence answer to the substance: what the old way was costing.","Close with motion: 'run it two weeks, then I want your read' — then next topic."],"focus":["impact","audience"]},
    {"id":"pressure-svc-mid-16","level":"mid","profession":"service","title":"The question, asked again","scenario":"On last month's call you answered the DM's turnover question with context about the industry. This month she asks again, slower: 'Why is YOUR store's turnover twice the district average?' The repeat means your first answer read as a dodge. This one can't.","task":"Write the direct answer you should have given: the store-specific causes, owned.","tips":["Kill the industry framing — she benchmarked you against the district on purpose.","Name your causes: the closing structure and a hiring mistake, both yours to fix.","'Twice the average is on me, and here's what changed' resets your credibility."],"focus":["clarity","impact"],"placeholder":"The honest answer is two things specific to us: the 1am closing structure, and a bad hiring rush in March."},
    {"id":"pressure-svc-mid-17","level":"mid","profession":"service","title":"'When exactly?'","scenario":"The espresso machine's been down two days and a regular asks, edged: 'So when exactly is it fixed?' You genuinely don't control the technician's schedule. 'Hopefully soon' is the answer that loses regulars. Commit to what you can actually commit to.","task":"Write the answer with a real commitment in it — a date, or a dated update.","tips":["Commit to the thing you control: 'I'll know the repair date by 2pm today.'","Offer the bridge: pour-over on the house until it's back.","Vague reassurance spends trust; a small kept promise builds it."],"focus":["precision","audience"],"placeholder":"The tech confirms his slot by 2pm today, and I'll post it the minute I know. Until it's back, pour-overs are on us."},
    {"id":"pressure-svc-mid-18","level":"mid","profession":"service","title":"'How could you let this happen?'","scenario":"You lead a care team, and a resident's daughter confronts you: her mother waited 40 minutes for help after pressing her call button. 'How could you let this happen?' is grief wearing anger. Defending the staffing ratio right now would be answering the wrong question.","task":"Script your response: acknowledge, give the facts straight, and commit to a specific follow-up.","tips":["Meet the feeling first: 40 minutes is too long, full stop.","Then facts without hiding: what the log shows, what you've verified so far.","Commit to something checkable: a review of that shift's response times, shared with her Friday."],"focus":["audience","impact"]},
    {"id":"pressure-svc-mid-19","level":"mid","profession":"service","title":"Defending the hours budget","scenario":"Head office wants every store to cut labor hours 8%, and on the call you get one shot: 'Give me a reason your store should be the exception.' You have one good argument — your store is the district's test site for the new service model — and thirty seconds.","task":"Write the 30-second case: the reason, the evidence, and the specific exception you're asking for.","tips":["Lead with the argument, not the plea: cutting hours mid-pilot destroys the pilot data.","One number: the pilot's early lift, which the cut would erase.","Ask for something specific and small: exemption until the pilot ends in eight weeks."],"focus":["impact","structure"],"placeholder":"One reason: we're the test site. Cut our hours mid-pilot and the district loses clean data on a model that's lifting sales 7%."},
    {"id":"pressure-svc-mid-20","level":"mid","profession":"service","title":"'What aren't you telling me?'","scenario":"After your polished monthly update, the owner leans back: 'This all sounds great. What aren't you telling me?' There IS something — a simmering conflict between your two best cooks you'd hoped to resolve quietly. The question is a trust test with exactly one right answer.","task":"Write the honest answer: the thing, its current state, and why you hadn't raised it yet.","tips":["Name it now — being caught managing the news costs more than the news.","Give its true status: contained, being handled, here's my plan.","Explain the hold-back without excuse: 'I wanted to fix it before reporting it. That was the wrong call.'"],"focus":["clarity","impact"],"placeholder":"One thing. My two best cooks aren't speaking, and I've been trying to fix it quietly before bringing it to you."},
    {"id":"pressure-svc-mid-21","level":"mid","profession":"service","title":"Your biggest failure, out loud","scenario":"You're interviewing for the area-manager role and the panel asks for your biggest failure as a manager. The dodge answers — 'I care too much' — are disqualifying at this level. You have a real one: you kept a toxic high-performer eight months too long.","task":"Script the answer: the failure named plainly, the cost, and what you changed.","tips":["Name it without flinching: what you did, what it cost the team.","The learning must be specific: what you now do differently, with an example.","A real failure answered well outscores a fake one every time."],"focus":["impact","structure"]},
    {"id":"pressure-svc-mid-22","level":"mid","profession":"service","title":"The vendor blames your staff","scenario":"The linen supplier missed Saturday's delivery and, on the phone, claims your closing crew 'never put the order in properly.' You have the confirmation email with a timestamp. The temptation is heat; the win is facts delivered evenly.","task":"Write what you say: the fact that settles it, and the resolution you need, without a single hot word.","tips":["Lead with the evidence, flat: 'The order was confirmed by your system Tuesday 4:12pm — I'm looking at the email.'","Skip the character debate entirely; the timestamp argues for you.","Move straight to remedy: today's delivery by 3, and the weekend charge credited."],"focus":["precision","impact"],"placeholder":"Our order was confirmed by your system Tuesday at 4:12pm — I have the email. What I need now is today's delivery by 3."},
    {"id":"pressure-svc-mid-23","level":"mid","profession":"service","title":"Yes or no: ready for the audit?","scenario":"The owner asks: 'Yes or no — are we ready for Friday's brand audit?' The true answer is 95% yes with one gap: the back storage area fails the labeling standard. Under a yes-or-no demand, the skill is giving the verdict first and the caveat second, not mushing them.","task":"Write the answer: verdict first, the one gap with its fix-by time, nothing else.","tips":["Pick the verdict the facts support: 'Yes, with one exception I'm closing Thursday.'","The caveat gets one sentence and a deadline, not a paragraph.","A crisp qualified yes reads stronger than an unqualified one they later disprove."],"focus":["clarity","concision"],"placeholder":"Yes — with one exception. Back storage fails the labeling standard today; it's fixed by Thursday close."},
    {"id":"pressure-svc-mid-24","level":"mid","profession":"service","title":"The tips-law question","scenario":"In the huddle, a server asks whether the new tip-pool structure is even legal for kitchen staff to be included. You genuinely don't know — it varies by jurisdiction and you've never checked. Ten people are waiting, and a confident wrong answer here could be expensive.","task":"Script the answer: the honest gap, the commitment, and the interim guidance.","tips":["Don't improvise employment law: 'Good question, and I'm not going to guess at it.'","Commit with a date: 'I'll have the real answer from the owner's accountant by Friday's huddle.'","Freeze the status quo in the meantime so nobody acts on a guess."],"focus":["clarity","audience"],"placeholder":"Good question and I won't guess at employment law. Here's what I'll do: the accountant's answer, in writing, by Friday's huddle."},
    {"id":"pressure-svc-mid-25","level":"mid","profession":"service","title":"Three questions, sixty seconds","scenario":"The owner calls between meetings: 'I've got one minute. Where's the month landing, is the new hire working out, and what happened with the freezer?' Three answers, headline-only, in the order asked — the format IS the test.","task":"Script the sixty-second spoken reply: three headline answers, no detail unless it changes a decision.","tips":["One sentence each, same order they asked: the number, the verdict, the status.","Flag which one needs a real conversation later — that's the only expansion allowed.","Finishing with seconds to spare is the whole performance."],"focus":["concision","structure"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-svc-mid-01","level":"mid","profession":"service","title":"The loyalty program, before and after","scenario":"You want the owner to fund a simple loyalty card. Your draft lists features: stamps, a free tenth coffee, an app option. Features don't move decisions. The persuasive version shows two futures: the regular who drifts away versus the regular who's locked in.","task":"Rewrite the pitch as a before/after: where we are, where we could be, and the bridge.","tips":["Before: we don't know our regulars' names in the till data, and they owe us nothing.","After: 300 identified regulars with a reason to pick us over the new place.","The program is just the bridge — sell the far bank, not the plank."],"focus":["impact","structure"],"placeholder":"Right now our best customers have no reason to pass the new café on the corner. Picture instead:"},
    {"id":"narrative-svc-mid-02","level":"mid","profession":"service","title":"The keyholder story, objection first","scenario":"You're pitching the owner on training a second keyholder, and you know exactly what they'll say: 'That's another wage bump for something we rarely need.' A pitch that ignores the known objection loses to it. A pitch that opens with it disarms it.","task":"Write the pitch that raises the cost objection yourself and answers it before making the ask.","tips":["Say their line before they do: 'This costs a $1/hour bump, about $2,000 a year.'","Then the counterweight: one missed open costs a day's sales — $2,400 — plus the trust of everyone who stood outside.","Steelmanning the objection is what makes the yes feel safe."],"focus":["impact","structure"],"placeholder":"The honest cost first: a keyholder bump runs about $2,000 a year. Here's what it insures against:"},
    {"id":"narrative-svc-mid-03","level":"mid","profession":"service","title":"One guest's forty minutes","scenario":"Ticket times have crept up and your kitchen has stopped feeling it — 'average ticket time up 6 minutes' lands as a statistic. Last Thursday a couple celebrating a promotion waited forty minutes, watched two later tables get served, and left without dessert. That's the same data with a face.","task":"Write the huddle story version: the couple's evening as the kitchen would have seen it if they'd been at the table.","tips":["Tell it in sequence with the waiting felt: ordered at 7:10, watched table 12 get served at 7:35.","No blame in the telling — the story indicts the system, not a person.","Land on the connection: the 6-minute average is made of nights like theirs."],"focus":["impact","audience"],"placeholder":"Thursday, table 9: a couple celebrating her promotion. They ordered at 7:10. At 7:35 they watched table 12 — seated after them — get food."},
    {"id":"narrative-svc-mid-04","level":"mid","profession":"service","title":"The patio, as a bridge","scenario":"The unused side lot could hold twelve patio tables, and you want the owner to spend $18,000 building it. Your draft is a cost breakdown. The persuasive frame is a change story: the summer you're currently losing, the summer you could be having, and the lot as the bridge between them.","task":"Write the three-part pitch: current state, possible state, bridge — with one number in each part.","tips":["Current: June to September we turn away roughly 30 parties a week in good weather.","Possible: twelve tables at two turns a night is real revenue — size it.","Bridge: $18k, open by June 1, payback by August. The number feels different at the end of a story."],"focus":["structure","impact"],"placeholder":"Every warm Friday we turn away about a dozen parties while the side lot stores two dumpsters. Here's the other version of this summer:"},
    {"id":"narrative-svc-mid-05","level":"mid","profession":"service","title":"The tip pool, as a story","scenario":"The tip-pool announcement you drafted explains the formula. Formulas don't persuade sceptical servers; futures do. The story that persuades: the Tuesday closer who works as hard as the Saturday crowd-surfer and goes home with a third of the tips — and what the pool does to that.","task":"Rewrite the announcement around one concrete before/after shift comparison.","tips":["Pick the sympathetic case everyone recognizes: the strong worker on the dead shift.","Show her Tuesday, before and after the pool, in dollars.","Then be honest about who gives ground: big Saturdays share more. Persuasion survives honesty; spin doesn't."],"focus":["audience","impact"],"placeholder":"Take a real Tuesday close — same work, same hustle, $31 in tips. Under the pool, that same shift pays:"},
    {"id":"narrative-svc-mid-06","level":"mid","profession":"service","title":"'We tried that before'","scenario":"You're pitching the DM on a breakfast pilot, and you know the response: 'We tried breakfast in 2022 and it flopped.' They're right — it did. Your pitch has to make 2022 evidence FOR you: what's different now, named precisely, or the objection wins by default.","task":"Write the pitch section that takes on the 2022 failure directly and turns it.","tips":["Concede the history fully — minimizing it costs you the room.","Name what's changed: the office tower opened, foot traffic before 9am is up 60%.","'Same idea, different conditions' only works if you can name the conditions."],"focus":["impact","precision"],"placeholder":"You're right that 2022 breakfast failed. Two things are different now, and they're the two that killed it then:"},
    {"id":"narrative-svc-mid-07","level":"mid","profession":"service","title":"The waste log tells a story","scenario":"The kitchen ignores the waste numbers you post weekly. Numbers nag; stories teach. This week's log, read differently, is a story: every Sunday you prep for the Saturday that already happened, and every Monday you throw the extra away.","task":"Write the huddle version that turns the waste pattern into a story with a villain (the habit, not a person).","tips":["Find the pattern's plot: we prep Sunday like it's Saturday, and Monday's bin proves it.","The villain is the habit — 'we cook for yesterday' — never a cook.","End with the single change the story demands: Sunday pars set from Sunday data."],"focus":["impact","structure"],"placeholder":"Here's what the waste log actually says: every Sunday we cook for the Saturday that already happened."},
    {"id":"narrative-svc-mid-08","level":"mid","profession":"service","title":"Selling the training hour","scenario":"You're introducing a paid weekly training hour and your veterans see it as an insult — they've poured coffee for ten years. The frame that fails: 'everyone needs training.' The frame that works: what's in it for them, concretely — the tickets they hate, the tips they're leaving on the table.","task":"Write the pitch to veterans that frames the hour around their interest, not their deficiency.","tips":["Open by crediting what they already know — the hour builds on it, doesn't question it.","Make the payoff theirs: the new menu's wine pairings are pure tip money.","One veteran as co-teacher changes the room's chemistry — name that plan."],"focus":["audience","impact"],"placeholder":"You've forgotten more about this floor than the new menu knows. The hour isn't remedial — it's the wine list, and the wine list is tips."},
    {"id":"narrative-svc-mid-09","level":"mid","profession":"service","title":"The recruiting pitch that isn't generic","scenario":"Your job ad says 'competitive pay, great team, fast-paced environment' — the same three phrases as every ad on the board. You have real material: two of your last three shift leads got promoted within a year, and the schedule is posted three weeks out, not three days.","task":"Rewrite the pitch paragraph around your two provable differences.","tips":["Claims candidates can check beat adjectives they've learned to skip.","'Schedule posted three weeks out' speaks directly to the industry's biggest pain.","The promotion stat is a story in one line: name what those two people do now."],"focus":["audience","precision"],"placeholder":"Two things we do differently: your schedule is posted three weeks ahead, not three days. And two of our last three shift leads —"},
    {"id":"narrative-svc-mid-10","level":"mid","profession":"service","title":"The deep-clean day","scenario":"You want to close for one Monday — a full revenue day — for a top-to-bottom deep clean and reset. The owner hears 'lose a day's sales.' The story you need to tell: what the slow slide of 'we'll get to it' costs, and what walking into a reset building does to a team.","task":"Write the pitch that makes the closed Monday an investment story, not a cost.","tips":["Name the drift honestly: the walk-in shelving, the vent hoods, the storage room nobody opens for guests.","Cost the alternative: piecemeal cleaning during service never gets there and slows every shift.","One Monday is $1,900 in sales; a failed inspection is the other story. Tell both."],"focus":["impact","structure"],"placeholder":"I want to spend one Monday — about $1,900 in sales — to buy back the building. Here's the drift we can't clean during service:"},
    {"id":"narrative-svc-mid-11","level":"mid","profession":"service","title":"The price increase, framed true","scenario":"Menu prices go up 6% next month and you're writing the note to regulars. The defensive frame — 'due to rising costs beyond our control' — reads like every corporate apology. The truthful persuasive frame: what the money protects, named specifically.","task":"Write the 3-4 sentence note that frames the increase around what it preserves.","tips":["Name what doesn't change: the butcher you buy from, the portion, the person cooking it.","One honest sentence on costs — specifics ('beef is up 22%') read as candor, not excuse.","Regulars don't leave over 6%; they leave over feeling processed. Write like a person."],"focus":["audience","impact"],"placeholder":"Next month most prices rise about 6%. Here's what that buys: the same butcher, the same portions, the same kitchen —"},
    {"id":"narrative-svc-mid-12","level":"mid","profession":"service","title":"The reservation system, sold twice","scenario":"You're proposing a paid reservation system, and your audience is really two: the owner (who feels the no-shows) and the host team (who fear being replaced by an iPad). One pitch, two stakes — the proposal has to speak to both or one of them quietly kills it.","task":"Write two short before/after framings of the same change: one for the owner, one for the hosts.","tips":["Owner's story: eleven no-show tables a week become three, with deposits on big parties.","Hosts' story: the iPad takes the phone tag, they keep the judgment calls and the guest relationships.","Same facts, different futures — that's audience-shaped narrative, not spin."],"focus":["audience","structure"],"placeholder":"For the owner: eleven no-shows a week, deposits on parties of six-plus. For the host team, the honest version:"},
    {"id":"narrative-svc-mid-13","level":"mid","profession":"service","title":"The objection you'd rather skip","scenario":"Your delivery-app proposal is strong except for one thing you've been avoiding: the 28% commission genuinely wrecks margin on your cheapest items. The owner will find it in four minutes. Address it yourself — with your real answer — or lose the room when they do.","task":"Write the pre-emption paragraph: state the strongest objection at full strength, then your answer.","tips":["State it stronger than they would: 'On a $9 sandwich, 28% commission makes us zero.'","Your answer must be real: a delivery-only menu priced for the channel.","Burying a known weakness converts one problem into two — the weakness, and your hiding of it."],"focus":["impact","precision"],"placeholder":"The strongest argument against this is the commission: 28% turns our $9 items into charity. So the delivery menu doesn't have $9 items."},
    {"id":"narrative-svc-mid-14","level":"mid","profession":"service","title":"3.8 stars, translated","scenario":"Your team shrugs at the 3.8 review average — it sounds fine, like a B-minus. Translated into behavior it isn't fine: at 3.8, you're below the filter line many people set when choosing where to eat. The number needs to become a picture of a customer choosing.","task":"Write the huddle explanation that turns 3.8 into a story about one potential customer's thumb.","tips":["Show the moment: someone new to the neighborhood, two cafés on the map, one shows 4.4.","'We lose people who never come in' is invisible loss — the story makes it visible.","End with the reachable number and what moves it: 4.2 is twenty good reviews away."],"focus":["audience","impact"],"placeholder":"Picture someone who just moved here, phone out, two cafés on the map. We're the 3.8. They will never know what we're like —"},
    {"id":"narrative-svc-mid-15","level":"mid","profession":"service","title":"The section-team story","scenario":"You're switching the floor from solo sections to two-person teams, and the huddle announcement will meet folded arms — veterans like owning their tables and their tips. You believe in the change because of what happened the night Ana and Luis improvised it during the storm rush.","task":"Script the huddle pitch built around that one night, ending with the trial terms.","tips":["Tell the Ana-and-Luis night as it happened: the rush, the improvisation, the numbers at close.","A story from inside the room persuades where a policy from above can't.","End with terms that respect the skeptics: three weekends, then we look at the tip data together."],"focus":["impact","audience"]},
    {"id":"narrative-svc-mid-16","level":"mid","profession":"service","title":"Moving the landlord","scenario":"The parking-lot lighting has been half-dead for two months and the landlord ignores maintenance requests. Your emails have been polite lists. A landlord moves when the story makes inaction expensive: an incident in a dark lot lands on the property owner too.","task":"Rewrite the request as a stakes narrative: what the darkness invites, and what both parties stand to lose.","tips":["Paint the specific scene, not the abstraction: staff walking to cars at midnight, the incident report waiting to happen.","Make the shared stake explicit — liability reaches the property owner.","Close with the easy exit: the quote you already got, one signature from action."],"focus":["impact","audience"],"placeholder":"Since March, my closers walk to their cars in the dark — the lot's east fixtures are all out. If anything happens out there, it lands on both of us."},
    {"id":"narrative-svc-mid-17","level":"mid","profession":"service","title":"The case for Rosa","scenario":"You want to promote Rosa to shift lead over an external hire with more years on paper. To the owner, this is a resume comparison Rosa loses. Your case is a story the resume can't hold: the night the till crashed on Boxing Day and what Rosa did without being asked.","task":"Write the promotion case built on the Boxing Day story plus one number.","tips":["Tell the story with the decisive detail — what she did that wasn't her job.","Pair it with one number: her shifts' comp rate, her section's repeat guests.","Frame the external risk honestly: a stranger's references versus two years of watching Rosa decide."],"focus":["impact","structure"],"placeholder":"On Boxing Day the till crashed at peak with a line to the door. Rosa, unasked, had the floor on handwritten tickets in four minutes."},
    {"id":"narrative-svc-mid-18","level":"mid","profession":"service","title":"Arguing against the cut","scenario":"Head office plans to cut your store's evening hours because the 8-10pm register data looks thin. What the data misses: the care workers from the facility next door who shop at 9pm because nothing else is open, and what they buy isn't big but it's every single night. You get one email to make the case.","task":"Write the email that pairs the human pattern with the numbers that support keeping the hours.","tips":["Lead with the story the spreadsheet can't see: who's in the store at 9pm and why.","Then the supporting math: basket count, its consistency, the sister-store precedent.","Ask for a measured alternative: a six-week measured trial before the cut, with the decision criteria agreed upfront."],"focus":["audience","impact"],"placeholder":"Before we cut 8-10pm, one thing the register data doesn't show: the night-shift care workers next door, in our aisles at 9pm every single night."},
    {"id":"narrative-svc-mid-19","level":"mid","profession":"service","title":"The community night pitch","scenario":"You want the owner to host a monthly fundraiser night for the local youth league — 15% of the evening's sales donated. The soft pitch ('it's good for the community') is easy to decline. The business story — what a room full of league families does on a dead Wednesday — is harder to.","task":"Write the pitch that carries both the heart and the math, in that order.","tips":["Open with the picture: forty families on a Wednesday that normally does thirty covers total.","Then the math: even at 15% donated, the night beats a normal Wednesday by half.","The heart earns the meeting; the math earns the yes. Bring both."],"focus":["impact","structure"],"placeholder":"Wednesdays do thirty covers. A youth-league fundraiser night brings forty families through the door —"},
    {"id":"narrative-svc-mid-20","level":"mid","profession":"service","title":"The improvement arc","scenario":"Complaint counts are down 40% since March, but your team only ever hears the fresh complaints — every huddle is the newest failure. They think they're losing. The data says they're winning, and nobody has told them the story of the arc.","task":"Write the huddle message that tells the three-month arc as a story with the team as protagonist.","tips":["Start where March actually was — the specific bad week they all remember.","Mark the turn: the change they made, in their hands, that bent the line.","Today's complaint still gets fixed — but inside a winning story, not a losing one."],"focus":["impact","audience"],"placeholder":"Quick story. In March we logged 22 complaints in one week — you remember it. Last week: 6. Here's what you did in between."},
    {"id":"narrative-svc-mid-21","level":"mid","profession":"service","title":"Winning back Dana","scenario":"Dana, the best bartender you've ever had, left four months ago for a place that's now cutting her hours. You want her back. The pitch that fails: 'we miss you, the door's open.' The pitch that works names what pushed her out and what's different now — specifically.","task":"Write the message that owns why she left and makes the changed reality concrete.","tips":["Name her real reason for leaving before she has to — it proves you understood.","What's different must be checkable: the closing structure changed, the bar-back role is filled.","Make the ask specific and low-pressure: one conversation, her old Saturday back, a number."],"focus":["audience","impact"],"placeholder":"You left because the 1am closes with no bar-back were unsustainable — you were right. Both of those things have changed."},
    {"id":"narrative-svc-mid-22","level":"mid","profession":"service","title":"Why standards, the story version","scenario":"Your standards talks have all been lists: uniforms, phones, side work. Lists breed compliance at best. The story under the list is better: this is the neighborhood's third-favorite spot, the gap to first is small, and the gap IS the details — you've watched it close before.","task":"Write the opening two minutes of the standards talk as a story about what the details are for.","tips":["Give the details a destination: the details are the gap between third-favorite and first.","Use a real remembered moment when the room ran at full standard and everyone felt it.","Then the list lands as tactics for a campaign, not rules from above."],"focus":["impact","structure"]},
    {"id":"narrative-svc-mid-23","level":"mid","profession":"service","title":"The dishwasher's payback story","scenario":"The commercial dishwasher is on its last legs and the replacement is $6,800. Your draft says 'we really need this.' The persuasive version is arithmetic wearing a story: what the machine's failures already cost per month, and the date the new one finishes paying for itself.","task":"Write the pitch with the payback math as its spine.","tips":["Current cost, itemized: repair calls, rewash labor, the Saturday it died mid-service.","The monthly bleed makes the price a comparison, not a number: $6,800 once versus $560 a month forever.","Name the break-even date out loud — 'paid for by March' is the whole argument."],"focus":["precision","impact"],"placeholder":"The old machine costs us about $560 a month — two repair calls, rewash labor, and one dead Saturday. The new one is $6,800:"},
    {"id":"narrative-svc-mid-24","level":"mid","profession":"service","title":"Steelmanning the marketing spend","scenario":"You want $400 a month for local social ads, and the owner believes marketing money evaporates — because for years, theirs did. The pitch must open with their strongest case, fully granted: the radio spots and flyer drops that provably did nothing.","task":"Write the pitch that grants the history and then distinguishes the proposal on measurability.","tips":["Grant it whole: 'You spent $5k on radio and couldn't trace one customer to it. That was real.'","Distinguish on the mechanism: this spend is trackable to the redemption code, weekly.","Offer the kill switch: any month it doesn't pay for itself twice over, it stops. Reversibility persuades."],"focus":["impact","structure"],"placeholder":"You're right that the radio money vanished — $5k and not one traceable customer. This is different in exactly one way: we can count it."},
    {"id":"narrative-svc-mid-25","level":"mid","profession":"service","title":"Next quarter, painted","scenario":"You're closing the quarterly sit-down with the owner. The review part went fine; now the ending decides the mood. A trailing-off 'so, yeah, that's the quarter' wastes the moment. The strong close paints next quarter specifically enough that the owner can see it — and funds it.","task":"Script the closing 60 seconds: the picture of next quarter, the two things it requires, and the first step this week.","tips":["Paint with specifics, not adjectives: the patio full on a Thursday, the second keyholder opening without you.","Attach the two requirements plainly — this future has a price, and you're naming it now.","End with motion: the one thing you'll do this week either way."],"focus":["impact","structure"]}
  ],
  "delivering-hard-messages": [
    {"id":"hard-svc-mid-01","level":"mid","profession":"service","title":"The hours cut, said straight","scenario":"Slow season means you're cutting a server's weekly hours from 32 to 20, and she counts on those hours. Your drafted message spends four sentences on the season and the budget before the number appears. She'll read the wind-up and know something's coming — that dread is the cruelty.","task":"Rewrite the message with the change in sentence one and the honest context after.","tips":["Headline first: hours are dropping from 32 to 20 starting the week of the 4th.","Then the truth in one sentence: it's the season, not her performance — and say that explicitly.","End with what's real: first call when hours come back, and any shifts elsewhere you can offer."],"focus":["clarity","audience"],"placeholder":"I have hard news: your hours drop from 32 to 20 starting the week of the 4th. This is the season, not your work —"},
    {"id":"hard-svc-mid-02","level":"mid","profession":"service","title":"No discount for the regular","scenario":"A beloved regular — in three times a week for years — asked to book his daughter's graduation party at 'a friendly rate.' You can't; party margins are already thin and one exception becomes a policy. Warmth and the no have to live in the same short message.","task":"Write the reply that declines cleanly and keeps the relationship whole.","tips":["The no comes early and unhedged — a maybe-shaped no breeds a second ask.","Give the reason once, honestly: party pricing is already at the floor.","Add something true and warm that isn't a discount: the best room, a round of toasts on you."],"focus":["clarity","audience"],"placeholder":"I can't discount the party rate — even for you, and you're the closest thing we have to family here. What I can do:"},
    {"id":"hard-svc-mid-03","level":"mid","profession":"service","title":"The termination, first sentence","scenario":"After three documented warnings, today you're letting a server go. In the back office, with HR's checklist done, the whole conversation turns on your first sentence. Anything that starts with 'so, how are things going?' is a small betrayal — he'll replay this conversation for weeks.","task":"Script your opening two sentences: the decision, stated with plain respect, and what happens next.","tips":["The decision is the first sentence: 'This is your last shift — we're ending your employment today.'","No fake suspense, no feedback sandwich; he should never wonder what the meeting is.","Second sentence is logistics: final pay, the letter, references. Certainty is the kindness available."],"focus":["clarity","impact"]},
    {"id":"hard-svc-mid-04","level":"mid","profession":"service","title":"The overrun, reported early","scenario":"The bar renovation will run $4,000 over and finish two weeks late, and you've known for three days. Every day you sit on it, the owner loses options. Your draft opens with the good parts of the project. Bad news ages badly; it needs to lead.","task":"Write the message: the overrun and delay in sentence one, cause in sentence two, options in sentence three.","tips":["Numbers first: $4k over, two weeks late. The good parts can wait.","One-sentence cause without blame-shuffling: the wall opened up worse than the quote assumed.","Bring choices: eat it, trim the scope, or pause — with your recommendation attached."],"focus":["clarity","structure"],"placeholder":"The reno will come in $4k over and two weeks late — I want you to hear it now, while we still have choices."},
    {"id":"hard-svc-mid-05","level":"mid","profession":"service","title":"Feedback on the eye-rolls","scenario":"A talented server rolls her eyes at kitchen staff and new hires, and it's poisoning the room. 'Your attitude needs work' is unusable feedback — vague, personal, and deniable. What you have is behavior: specific moments, observable, with effects you can name.","task":"Write the feedback: two observed behaviors with their effect, and the specific change you need.","tips":["Behavior, not character: 'Tuesday, when Marco misread the ticket, you rolled your eyes and walked away.'","Name the effect: he now double-checks everything with me instead of you.","The ask is behavioral too: when someone errs, tell them plainly or bring it to me — no theater."],"focus":["precision","audience"],"placeholder":"Two moments this week I need to raise. Tuesday, when Marco misread the ticket —"},
    {"id":"hard-svc-mid-06","level":"mid","profession":"service","title":"No bonus this year","scenario":"The team is expecting the December bonus that's come every year, and this year the numbers can't support it. The owner has left the announcement to you. A message that buries the news under three paragraphs of 'challenging year' context will be skimmed, misread, and resented twice.","task":"Write the announcement: the news up front, the honest reason, and what is still true.","tips":["Say it in the first line — they'll forgive the news faster than they'd forgive a runaround.","One real reason with a number beats vague 'headwinds' language.","Name what stands: jobs are secure, the January raise cycle still happens. Only if true."],"focus":["clarity","impact"],"placeholder":"There's no December bonus this year, and I'd rather tell you straight than dress it up. Here's the why:"},
    {"id":"hard-svc-mid-07","level":"mid","profession":"service","title":"Declining the upsell","scenario":"Your coffee supplier's rep — who has been genuinely good to you — is pushing a premium bean program with a tasting kit and a discount window. It's a fine product you don't need at a price that doesn't work. The relationship deserves a clean no, not a slow fade of unanswered texts.","task":"Write the decline that is prompt, final, and keeps the good relationship.","tips":["Decline in the first sentence, thank in the second — not the reverse.","One reason, real: the current program fits our volume and our menu.","Close the loop but leave the door: 'ask me again when we open the second location.' Only if you mean it."],"focus":["concision","audience"],"placeholder":"I'm going to pass on the premium program — it's a good product that doesn't fit our menu or margins right now."},
    {"id":"hard-svc-mid-08","level":"mid","profession":"service","title":"The promotion that went elsewhere","scenario":"Two people wanted the sous chef role; you chose the newer cook, and now you owe the ten-year veteran the conversation. He'll hear the decision through whatever you say first, so say the decision first — then the parts he'll actually be able to use.","task":"Script the conversation opening: the decision, the specific reason, and what would change the next one.","tips":["No suspense: 'I've given the sous role to Kim, and I want to tell you why directly.'","The reason must be real and specific — a vague 'it was close' helps nobody.","Give him a path with edges: the two things that, done over six months, make him the next call."],"focus":["clarity","audience"]},
    {"id":"hard-svc-mid-09","level":"mid","profession":"service","title":"The write-up conversation","scenario":"You're delivering a formal written warning for lateness — the conversation that makes the paper real. The trap is drowning it in reassurance until he leaves thinking it was a friendly chat. He should leave knowing exactly where the line is and exactly what crossing it costs.","task":"Script the core of the conversation: what this is, the record, the standard, and the consequence — in four sentences.","tips":["Name the thing: 'This is a formal written warning, and it goes in your file.'","The record is dates, not vibes — read them.","State the consequence as fact, not threat: the next unexcused late is a final warning. Then let silence do its work."],"focus":["precision","impact"],"placeholder":"This is a formal written warning for attendance — I want to be straight about what it is and what happens next."},
    {"id":"hard-svc-mid-10","level":"mid","profession":"service","title":"Cancelling the party","scenario":"A double-booking error — yours — means you have to cancel a 30-person birthday party with nine days' notice. The message you send will be screenshot and shared. It needs the apology, the truth, and a make-good generous enough to be the story instead of the cancellation.","task":"Write the message: the news, the honest ownership, and the concrete make-good.","tips":["News first, ownership immediately: 'we double-booked, and the error is mine.'","No passive fog — 'a scheduling conflict has arisen' makes it worse.","The make-good must cost you something real: full deposit back plus the private room at half price on three alternate dates, held for 48 hours."],"focus":["clarity","impact"],"placeholder":"I have bad news and it's our fault: we double-booked your party on the 21st, and I can't host you that night."},
    {"id":"hard-svc-mid-11","level":"mid","profession":"service","title":"After the firing, the team","scenario":"You let a popular server go this morning — for cause you can't fully share. The rumor mill is already running. The team message has to be honest without violating privacy, final without inviting a trial, and respectful of both the person gone and the people staying.","task":"Write the team message that says what you can, marks what you can't, and steadies the room.","tips":["Confirm the fact plainly — pretending nothing happened feeds the rumor mill.","Draw the privacy line out loud: 'the reasons stay between us and them, as yours would.'","Redirect to the practical: how shifts are covered, and that the standard applied is the same for everyone."],"focus":["audience","concision"],"placeholder":"You'll have noticed Jamie is no longer with us — that's true as of this morning. The reasons stay private, as yours would."},
    {"id":"hard-svc-mid-12","level":"mid","profession":"service","title":"The slipping lieutenant","scenario":"Your assistant lead — once your best hire — has been coasting for two months: late closes, sloppy counts, short with the team. Everyone sees it, which means everyone is watching what you do. The kindest version of this conversation is the one that takes her seriously enough to be direct.","task":"Script your opening: the pattern named with two specifics, the standard, and the question you'll actually listen to.","tips":["Name the drop against her own bar: 'Two months ago your closes were the standard. Tuesday's count was $40 off, unlogged.'","Then genuinely ask what's going on — direct isn't the opposite of caring.","Separate support from standard: whatever the answer, the counts have to be right. Both things stay true."],"focus":["precision","audience"],"placeholder":"This conversation is because you set a standard here that you've stopped meeting — and I want to know what's going on."},
    {"id":"hard-svc-mid-13","level":"mid","profession":"service","title":"Saying no to the owner","scenario":"The owner wants to launch karaoke Tuesdays, starting next week. You think it's wrong for the room, wrong for the staff, and priced to lose money — and the owner signs your paycheck. Declining upward needs the same headline-first clarity, plus a professional's reasons and an alternative.","task":"Write the pushback message: your clear no, the two strongest reasons, and the counter-offer.","tips":["Disagree plainly, not around the edges: 'I don't think we should do this, and I want to make the case.'","Two reasons with numbers, not taste: the sound system cost, the Tuesday regulars we'd displace.","Offer the alternative that scratches the same itch: the trivia night that costs nothing to try. Then commit to executing whatever they decide."],"focus":["impact","structure"],"placeholder":"I want to push back on karaoke Tuesdays before we book anything — I think it loses money and costs us our Tuesday regulars."},
    {"id":"hard-svc-mid-14","level":"mid","profession":"service","title":"The refund refused","scenario":"A customer wants a full refund on a catering order that was delivered correct, on time, and — per your driver's photos — complete. She's loud in email and threatening reviews. The no has to be immovable without a single sentence she can screenshot as rudeness.","task":"Write the refusal: gracious, factual, final, and safe to be read by ten thousand strangers.","tips":["Lead with what you verified, not what she claimed: order, photos, timestamps.","The no is one clean sentence — repeated politely if needed, never re-argued.","Offer the thing that isn't a refund if there is one: a credit as goodwill, clearly labeled as goodwill. Write it knowing it may be published."],"focus":["precision","audience"],"placeholder":"I've reviewed the order, the delivery photos, and the timestamps, and the order was delivered complete and on time — so I won't be refunding it."},
    {"id":"hard-svc-mid-15","level":"mid","profession":"service","title":"The failed inspection, told to the team","scenario":"The health inspection came back with a conditional pass and two critical violations — both process failures the whole kitchen owns. The team meeting can go two ways: a blame hunt, or the most honest reset you've ever run. Your opening decides which.","task":"Script the meeting opening: the result stated plainly, the ownership framed, and the path.","tips":["The grade is the first sentence, unspun: conditional pass, two criticals, re-inspection in 30 days.","Take your share first — 'the checklist that failed is my checklist' — before asking for theirs.","End the opening with the plan's shape: three fixes, thirty days, everyone's name on one."],"focus":["clarity","impact"]},
    {"id":"hard-svc-mid-16","level":"mid","profession":"service","title":"Can't match the offer","scenario":"Your best line cook has a written offer from across town: $3 more an hour. You have room for $1. Stalling while he decides is the worst move; a fast, honest answer — even this one — is the respect that sometimes keeps people, and always keeps your name good.","task":"Write what you tell him: the honest number, the honest gap, and everything true besides money.","tips":["The number first, no theater: 'I can do $1 more — I can't get to $3, and I won't pretend I might later.'","Then the non-money truths, only if real: the schedule, the promotion timeline, the kitchen he'd be second in there.","End clean either way: if he goes, he goes with your reference. Say that out loud."],"focus":["clarity","audience"],"placeholder":"Straight answer: I can raise you $1, and I can't reach $3 — I won't string you along pretending otherwise."},
    {"id":"hard-svc-mid-17","level":"mid","profession":"service","title":"The star with the sharp edges","scenario":"Your highest-selling server also mocks slower coworkers in the group chat, and two of them have quietly asked to not share her shifts. High performers hear criticism as negotiation — the numbers, they assume, buy slack. This feedback has to sever that assumption cleanly.","task":"Write the conversation core: the numbers credited, the behavior named, and the non-negotiable.","tips":["Credit the sales in one honest sentence — then don't let them buy anything.","Specifics from the chat, quoted: deniability dies with the exact words.","The line, stated as a line: sales don't offset how you treat this team. Both excellent and kind — that's the job."],"focus":["impact","precision"],"placeholder":"Your numbers are the best on this floor — and they don't buy what I'm about to raise."},
    {"id":"hard-svc-mid-18","level":"mid","profession":"service","title":"Missing the quarter, said first","scenario":"Your store will miss its quarterly target by around 7%, and the area manager's review call is Thursday. Waiting to be asked is the junior move. The senior move is the Tuesday email: the miss, the size, the causes, and the plan — before anyone has to come looking.","task":"Write the email that breaks your own bad news first.","tips":["Subject line and first sentence both carry the miss — no soft launch.","Causes in two sentences, split honestly between the market's share and yours.","The plan gets specifics and dates; 'working hard to improve' is not a plan. Being first to your own bad news is the whole credibility play."],"focus":["clarity","structure"],"placeholder":"We're going to miss Q3 by about 7%, and I want you to have my read before Thursday's call."},
    {"id":"hard-svc-mid-19","level":"mid","profession":"service","title":"The swap you can't approve","scenario":"Normally you approve shift swaps without a thought. This one — your two newest hires trading into the same Saturday close, with no senior on — you can't. The no is easy; the trap is apologizing so much the rule sounds optional, or explaining so little it sounds arbitrary.","task":"Write the two-sentence decline: the no, the one-sentence rule behind it, and the alternative.","tips":["No first, reason once: every close needs one senior on — that's the whole rule.","Don't over-apologize a reasonable rule into an exception waiting to happen.","Offer the version that works: swap approved if one of them trades with Priya instead."],"focus":["concision","clarity"],"placeholder":"I can't approve this one — a close needs at least one senior on, and this swap leaves none."},
    {"id":"hard-svc-mid-20","level":"mid","profession":"service","title":"The carer is changing","scenario":"You lead a home-care team, and a client's family is deeply attached to Grace, who has been their father's carer for two years. Grace is moving away, and you're making the call. For them this is not a roster change; it's a loss in a year full of them. It still has to be said in the first breath.","task":"Script the call opening: the news gently but immediately, what stays the same, and the transition plan.","tips":["Say it in the first two sentences — long preamble on a call like this reads as bad news about their father.","Honor the relationship without dramatizing: two years matters, name it.","The plan is the comfort: Grace overlaps with the new carer for two weeks, and you'll personally check in after."],"focus":["audience","clarity"]},
    {"id":"hard-svc-mid-21","level":"mid","profession":"service","title":"The supplier breakup","scenario":"After a year of short orders and missed windows, you're moving your produce account to another supplier. The rep is a good person at a struggling company, and he'll ask for one more chance — you've given three. The email should be final, factual, and clean enough to reread without wincing.","task":"Write the termination email: the decision, the record in brief, and the professional close.","tips":["Decision first, effective date attached — 'we're moving our account on the 1st.'","The record is two sentences of counted fact, not a grievance list.","Close with the handshake: what he did well, and that the door isn't welded shut. No blame theater."],"focus":["clarity","concision"],"placeholder":"We're moving our produce account to another supplier effective the 1st. This follows five short or late deliveries since March —"},
    {"id":"hard-svc-mid-22","level":"mid","profession":"service","title":"Stepping someone back down","scenario":"Six weeks ago you made Tom a keyholder; it hasn't worked — two unlocked doors, one missed alarm set, a till left uncounted. You're returning him to server, keeping his hours. The conversation must be unambiguous about the decision and genuinely open about the future.","task":"Script the demotion conversation: the decision, the three facts, and what stays intact.","tips":["Decision first, no maybe in it: 'I'm moving you back to server, starting Monday.'","Three facts, dated, no pile-on — the record speaks quietly.","Protect what's true: hours unchanged, pay adjusted honestly, and the specific gate for a second run at it in six months."],"focus":["clarity","precision"],"placeholder":"I'm taking the keys back and moving you to server from Monday — same hours. I owe you the exact reasons:"},
    {"id":"hard-svc-mid-23","level":"mid","profession":"service","title":"Renovation means fewer hours","scenario":"The two-month renovation cuts the floor to half capacity, and half capacity means everyone's hours shrink for eight weeks. The whole team hears this at once, and how you structure the message determines whether they plan around it or panic through it.","task":"Write the announcement: the news, the numbers, the fairness mechanism, and the end date.","tips":["All four facts in the first three sentences: what, how much, how allocated, until when.","The fairness mechanism matters most — cuts shared evenly by percentage, posted where everyone can check.","The end date is the anchor: hours restore November 1, in writing. Uncertainty, not scarcity, is what breaks teams."],"focus":["structure","audience"],"placeholder":"From Sept 1 the reno takes us to half capacity, which means hours drop about 30% across the board for eight weeks — shared evenly, restored Nov 1."},
    {"id":"hard-svc-mid-24","level":"mid","profession":"service","title":"The reason she didn't get it","scenario":"You turned down an interviewee for the host role, and she wrote back asking — politely, seriously — what she could have done better. The easy replies are the form letter or silence. She asked for the real thing; give her a real thing she can use, kindly edged.","task":"Write the reply: the decision reaffirmed, one genuine usable reason, and one genuine strength.","tips":["Reaffirm without reopening: the decision stands, and here's the honest why.","One specific, actionable gap — 'we needed weekend availability you couldn't offer' or the concrete skill — not a personality audit.","One true strength she should keep leading with. Real feedback is the rarest kindness in hiring."],"focus":["audience","precision"],"placeholder":"Since you asked seriously, here's the honest answer: the decision came down to one thing —"},
    {"id":"hard-svc-mid-25","level":"mid","profession":"service","title":"Your own mistake, reported","scenario":"You built the roster wrong: last Saturday ran three staff short at peak, tables walked, and the team got flattened for two hours. Nobody above you knows it was a roster error — the night could pass as bad luck. The message you send the owner decides what kind of manager you are.","task":"Write the message: your error named first, the cost stated, and the fix that prevents the repeat.","tips":["Open with ownership, no cushion: 'Saturday's meltdown was my roster error.'","Count the cost honestly — walked tables, the team's brutal night — you lose the right to round down.","The fix is structural, not a promise to try harder: the double-check step now built into posting. Owning it first is what makes the next 'not my fault' believable."],"focus":["clarity","impact"],"placeholder":"Saturday's chaos was my mistake — I posted the roster with three peak slots unfilled and didn't catch it."}
  ],
  "putting-it-together": [
    {"id":"together-svc-mid-01","level":"mid","profession":"service","title":"The complete incident email","scenario":"A guest fell on the back stairs last night, went to hospital for a wrist X-ray, and her son has already mentioned lawyers. The email you send the owner tonight has to do everything at once: lead with the point, stay precise, structure the facts, and end with owned next steps.","task":"Write the full email: headline, facts with times, actions taken, and your next three steps.","tips":["First line carries the whole event: what happened, current condition, the lawyer mention.","Facts section is timestamped and speculation-free — it may be read in a legal context.","Close owning the motion: report filed, insurer called Monday 9am, staff statements collected by Wednesday."],"focus":["structure","precision"],"placeholder":"Last night at 9:20 a guest fell on the back stairs; she's home after a wrist X-ray, and her son mentioned contacting a lawyer. Here's the full picture:"},
    {"id":"together-svc-mid-02","level":"mid","profession":"service","title":"The month in sixty seconds","scenario":"The area manager calls: 'Give me your month in one minute.' Everything you've practiced compresses into this: the verdict first, three signposted points, numbers not adjectives, and a clean stop before she has to cut you off.","task":"Script the sixty-second spoken summary of a month that had a sales record, a key resignation, and a passed inspection.","tips":["Verdict sentence first: record month, one staffing risk, inspection clean.","One sentence per item, each with its number.","Stop early. The unused fifteen seconds is the strongest thing you can say."],"focus":["concision","structure"]},
    {"id":"together-svc-mid-03","level":"mid","profession":"service","title":"The Monday message that does it all","scenario":"Monday's group-chat message has to carry four things: a schedule change, a new till procedure, a reminder about Friday's private event, and a genuine shout-out for Saturday's crew. Written badly, it's a wall nobody finishes. Written well, it's twenty seconds of total clarity.","task":"Write the complete message: ordered by what people need first, formatted to be skimmed, under 120 words.","tips":["Order by consequence: the schedule change affects everyone today — it leads.","One line per item, labeled, so a skimmer catches all four.","The shout-out goes last and lands hardest there — end on the good note."],"focus":["structure","concision"],"placeholder":"Four things this week. 1) SCHEDULE: Thursday's rotation changed —"},
    {"id":"together-svc-mid-04","level":"mid","profession":"service","title":"The reply that saves the guest","scenario":"A detailed, angry, fair complaint email: wrong dish, a 25-minute wait for the fix, an offhand comment from a server that stung. The full-stack reply acknowledges specifically, explains in one clause, remedies concretely, and reads well if she forwards it to two hundred people.","task":"Write the complete reply, four to six sentences.","tips":["Mirror her specifics — generic apology language tells her nobody read it.","One clause of explanation maximum; the wait was the failure, not the story behind it.","The remedy is specific and requires no work from her. Close with your name and direct line — accountability has a name on it."],"focus":["audience","impact"],"placeholder":"You waited 25 minutes for a dish we got wrong, and the comment you overheard made it worse — I'm sorry for all three, specifically."},
    {"id":"together-svc-mid-05","level":"mid","profession":"service","title":"The brunch proposal, full stack","scenario":"You're proposing Saturday brunch service to the owner in one page: the case, the numbers, the staffing, the risk. This is every module at once — BLUF the recommendation, structure the support, precise numbers, the objection pre-empted, and a decision made easy.","task":"Write the one-page memo's first half: recommendation, the three-part case, and the pre-empted objection.","tips":["Line one is the ask with its headline number: launch Saturday brunch; projected $2,100 per Saturday at 60% capacity.","Three labeled sections, one insight each — demand evidence, cost math, staffing plan.","Name the strongest objection (kitchen fatigue before dinner service) and your specific answer to it."],"focus":["structure","impact"],"placeholder":"Recommendation: launch Saturday brunch May 3. At 60% capacity it adds roughly $2,100 a week. Three parts to the case:"},
    {"id":"together-svc-mid-06","level":"mid","profession":"service","title":"The vacation handover, complete","scenario":"Ten days away — your first real break in two years — and the assistant lead holds the keys. The handover document is a test of everything: audience-first (what SHE needs, in her moments of need), structured by urgency, precise where it matters, concise everywhere.","task":"Write the document's skeleton and complete the emergency section in full.","tips":["Order by her worst moments: emergencies first, daily rhythm second, FYI last.","Emergency lines are symptom → action → number, one line each, findable in ten seconds.","Define her decision authority explicitly: what she decides alone, what warrants a text, what can wait ten days."],"focus":["structure","audience"],"placeholder":"EMERGENCIES FIRST. Walk-in dies: call ColdTech 555-0119, move stock to bar fridges, log temps hourly."},
    {"id":"together-svc-mid-07","level":"mid","profession":"service","title":"One pipe, three audiences","scenario":"A burst pipe floods the kitchen at 6am. Today is cancelled. Three messages, one hour: staff (don't come in, paid or not?), booked customers (tonight's reservations), and the owner (damage, insurance, timeline). Same fact, three completely different messages.","task":"Write all three messages, each shaped for its reader.","tips":["Staff need instructions and the pay answer — that's their whole question.","Customers need the cancellation, the apology, and the rebook path in two sentences.","The owner needs damage scope, insurance status, and reopening estimate — verdict first."],"focus":["audience","clarity"],"placeholder":"TO STAFF: Pipe burst overnight — do NOT come in today. You'll be paid for the scheduled shift."},
    {"id":"together-svc-mid-08","level":"mid","profession":"service","title":"The quarterly review, delivered whole","scenario":"Ninety minutes with the owner on the quarter. Your materials: one governing verdict, three evidenced points, one honest miss with its lesson, and two asks with numbers attached. The skill is the altitude — never drowning the story in shift-level anecdotes.","task":"Write your opening five sentences: verdict, the three-point map, and the first point with its number.","tips":["The verdict sentence does the work: 'a strong quarter that exposed one weakness worth fixing.'","Map before detail — three points, named, so the owner can hold the shape.","Anecdotes only as evidence for a named point, never as wandering color."],"focus":["structure","impact"]},
    {"id":"together-svc-mid-09","level":"mid","profession":"service","title":"The week-one email","scenario":"A new hire starts Monday. The email you send Friday sets up her whole first week: what to bring and wear, where to go, who mentors her, what the week covers, when you'll check in. Audience-first (she knows nothing), structured (she'll reread it three times), warm (she's nervous).","task":"Write the complete email, under 150 words.","tips":["Sequence it as she'll live it: Monday 8:45, back door, ask for Rosa.","One line per day for the week's shape — detail lives with the mentor.","End with the check-in promise and mean it: Friday, fifteen minutes, just you two."],"focus":["audience","structure"],"placeholder":"Welcome aboard — here's your whole first week in one email. Monday: arrive 8:45, back entrance, ask for Rosa (she's expecting you)."},
    {"id":"together-svc-mid-10","level":"mid","profession":"service","title":"The exception, argued upward","scenario":"Head office mandates closing at 9pm chain-wide; the summer festival on your street runs to 11pm for six weekends and your competitors will feast. The exception request email needs everything: BLUF ask, precise revenue math, the anticipated 'policy is policy' objection handled, and an easy yes.","task":"Write the complete request email, under 200 words.","tips":["The ask with its boundary in line one: extended hours, six named weekends, nothing beyond.","Numbers make exceptions grantable: last festival's 9-11pm window did $2,300 a night at the old hours.","Answer the precedent worry yourself: a defined, dated, reviewable exception — offer to report results after weekend two."],"focus":["impact","precision"],"placeholder":"Request: 11pm closes for the six festival weekends (June 14 - July 19), reverting automatically after. The math:"},
    {"id":"together-svc-mid-11","level":"mid","profession":"service","title":"The huddle after the viral post","scenario":"A TikTok mocking your restaurant's service hit 400k views overnight. The team saw it before you did; two of them are recognizable in it. Tonight's pre-shift huddle is the whole course in ninety spoken seconds: lead with the point, steady presence, honest hard message, and a team walking out taller.","task":"Script the ninety-second huddle: the acknowledgment, the facts, the protection, and tonight's job.","tips":["Name it immediately — pretending it doesn't exist hands the room to the phone screens.","Protect the two visible staff explicitly and out loud; that's what the team remembers.","Land on tonight: the response to a bad clip is three hundred good tables. Then run the huddle as normal — normalcy is the message."],"focus":["impact","audience"]},
    {"id":"together-svc-mid-12","level":"mid","profession":"service","title":"The write-up that survives review","scenario":"A bartender served a visibly intoxicated guest after a manager instruction not to — a liability event. The write-up you draft tonight may be read by HR, a lawyer, or a licensing board. Structure, precision, and zero editorializing, all at once, while you're still angry.","task":"Write the incident documentation: event, instruction given, observed violation, response — dated, factual, complete.","tips":["Write it as testimony: times, exact words of the instruction, what you observed directly.","Anger leaves no fingerprints on the page — no 'unbelievably,' no 'blatant.'","Separate observed fact from received report and label which is which. The document's calm IS its power."],"focus":["precision","structure"],"placeholder":"At 10:15pm I instructed J.M. not to serve the guest at seat 4 further alcohol. At approximately 10:40pm I observed —"},
    {"id":"together-svc-mid-13","level":"mid","profession":"service","title":"The renegotiation email","scenario":"Your bread supplier raised prices 9%; you've quietly gathered two competing quotes that are 5% below your CURRENT price. The renegotiation email is applied persuasion: lead with the relationship's value, put the precise numbers on the table, make the ask clean, and leave them a dignified path to yes.","task":"Write the complete email, firm and warm at once.","tips":["Open with what's true: four years, reliable, you'd rather stay.","The numbers do the confronting so your tone doesn't have to: their new price, the two quotes.","One clean ask with a date — match within 5% by Friday — and no bluff you won't honor."],"focus":["impact","precision"],"placeholder":"Four years in, you're our best supplier relationship, and I want to keep it that way — which is why I'm showing you these numbers instead of just moving."},
    {"id":"together-svc-mid-14","level":"mid","profession":"service","title":"The parking-lot pitch","scenario":"The district manager is walking to her car after a surprise visit that went well. You have ninety seconds of goodwill and one shot at the thing you actually need: her sponsorship for the second-keyholder budget that head office keeps deferring. Spoken, unscripted-sounding, complete.","task":"Script the ninety-second pitch: hook it to what she just saw, make the ask, give the one number, land the next step.","tips":["Anchor in the visit: 'You saw the morning run smoothly — here's the single point of failure behind it.'","One ask, one number, no submenu of extras.","The next step is hers and tiny: her name on the request when it hits her desk Thursday."],"focus":["concision","impact"]},
    {"id":"together-svc-mid-15","level":"mid","profession":"service","title":"The wedding, made right","scenario":"At Saturday's wedding reception the cake table collapsed — the couple laughed, the photographer caught everything, but the planner is furious and this planner books you six events a year. The follow-up email needs apology, precision about the cause, a real remedy, and the six-events relationship saved.","task":"Write the complete email to the planner.","tips":["Open with the unvarnished event and your ownership — she was there; spin insults her.","Cause in one precise sentence: the leg lock, now replaced on all folding tables. Systems, not excuses.","The remedy respects her business: the cake refunded to the couple, a credit on her next booking, and the new table-check step in writing."],"focus":["audience","structure"],"placeholder":"The cake table collapse was our failure — a leg lock that should have been checked and wasn't. Here's everything I've done since Saturday:"},
    {"id":"together-svc-mid-16","level":"mid","profession":"service","title":"The year-end message","scenario":"The last team message of the year: results the team earned, the hard patch nobody wants relitigated but everyone remembers, thanks that name real names and real moments, and next year framed with genuine appetite. Every skill, in a register that sounds like you.","task":"Write the complete year-end message, under 200 words.","tips":["The results come with their numbers — vague pride reads as no pride.","Touch the hard patch honestly in one sentence; skipping it makes the rest ring false.","Thanks with specifics: the name, the night, the thing they did. Generic gratitude thanks no one."],"focus":["impact","audience"],"placeholder":"Numbers first, because you earned them: best year in this building's history — up 9%, with review scores we've never hit before."},
    {"id":"together-svc-mid-17","level":"mid","profession":"service","title":"The claim narrative","scenario":"The insurance claim form for the kitchen flood has one intimidating box: 'Describe the incident and resulting losses.' What goes in it decides thousands of dollars. Chronological precision, complete loss inventory, zero speculation about cause, and every claim anchored to a document you actually have.","task":"Write the claim narrative: discovery, response timeline, and categorized losses with their evidence.","tips":["Timeline with timestamps: discovered 6:10am, water main off 6:25, plumber on site 7:40.","Losses in categories with documents attached: equipment (invoices), stock (waste log), revenue (last four Tuesdays' takings).","Describe what happened, never why — 'water from the ceiling junction' not 'faulty pipe.' Cause is the adjuster's job; overclaiming voids trust in every line."],"focus":["precision","structure"],"placeholder":"At 6:10am on March 4 I found standing water across the kitchen, source at the ceiling junction above the prep line. Timeline of response:"},
    {"id":"together-svc-mid-18","level":"mid","profession":"service","title":"One change, two scripts","scenario":"Delivery fees are going up $2 on all platform orders next month. Two artifacts needed: the customer-facing notice (posted and on the app) and the staff script for the inevitable counter question. Same fact, different audiences, both needing to feel fair in under forty words each.","task":"Write both: the customer notice and the two-line staff script.","tips":["Customer notice: the change, the date, one honest line of why, and the escape (pickup stays free).","Staff script must survive being said sixty times: neutral, short, with the pickup alternative built in.","Neither may argue or over-explain — fairness reads in brevity."],"focus":["audience","concision"],"placeholder":"NOTICE: From May 1, delivery orders carry a $2 platform fee increase. Pickup prices don't change."},
    {"id":"together-svc-mid-19","level":"mid","profession":"service","title":"Your store, in one paragraph","scenario":"The area-manager application asks: 'Describe a business result you drove and how.' One paragraph. Yours is real — you took a failing location to the district's top five — but the flat version ('improved sales through team development') says nothing. This paragraph is every skill compressed.","task":"Write the paragraph: situation, the two decisions that mattered, the measured result.","tips":["Open with the before-state in numbers — the turnaround only lands if the hole was real.","Two decisions, not six: the ones that actually moved it, with your reasoning visible.","Close with the after-numbers and the timespan. Result, mechanism, proof — no adjectives doing load-bearing work."],"focus":["structure","precision"],"placeholder":"I took over a store running 22% below plan with 70% annual turnover. Two decisions drove the turnaround:"},
    {"id":"together-svc-mid-20","level":"mid","profession":"service","title":"Saving the account","scenario":"Your biggest catering client — every-Friday office lunches, a fifth of weekday revenue — emails that they're 'reviewing options' after two late deliveries. The save requires everything: taking the point seriously, precise ownership of both incidents, a structural fix, and a reason to stay that isn't begging.","task":"Write the complete response email.","tips":["Take 'reviewing options' at full seriousness in the first line — minimizing it is the fatal move.","Both incidents get precise ownership: dates, causes, and the fix that's structural (the 11am departure rule), not apologetic.","Give them a reason beyond the fix: the standing 10% partner rate, the dedicated contact. End with confidence, not pleading."],"focus":["impact","audience"],"placeholder":"'Reviewing options' after two late Fridays is fair, and I want to earn the account back properly rather than talk you out of it."},
    {"id":"together-svc-mid-21","level":"mid","profession":"service","title":"The 11pm decision text","scenario":"Two servers clashed hard mid-shift; you separated them, sent one home, and finished the night short. It's 11pm and the owner needs to know before tomorrow's rumors arrive first. One text: what happened, what you decided, why, and what happens tomorrow — complete but phone-sized.","task":"Write the text message, under 80 words.","tips":["Event, decision, reason, next step — one clause each.","Your decision is stated as made, not floated for approval: you had the authority and used it.","Tomorrow's plan shows control: separate meetings at 2 and 3, resolution before Friday's shift."],"focus":["concision","clarity"],"placeholder":"Heads-up before you hear it elsewhere: J and M had a heated clash mid-shift. I separated them and sent J home —"},
    {"id":"together-svc-mid-22","level":"mid","profession":"service","title":"The allergy page, final form","scenario":"After the peanut near-miss, you're writing the allergy-protocol page that goes in the training binder — the version every future hire learns from. It has to be complete but scannable, precise but plain, ordered by the moment of need, with the non-negotiable unmissable.","task":"Write the complete one-page protocol: the rule, the steps in sequence, and the when-in-doubt line.","tips":["The non-negotiable leads in its own line: every allergy mention reaches the kitchen in writing, zero exceptions.","Steps in lived order: at the table, on the ticket, at the pass — with the exact words to use at each.","Close with the universal escape: unsure means stop and get the manager. Make that sentence impossible to miss."],"focus":["structure","clarity"],"placeholder":"THE RULE, ALWAYS: any allergy mention, however casual, goes to the kitchen in writing. No verbal-only relays, ever."},
    {"id":"together-svc-mid-23","level":"mid","profession":"service","title":"The one-pager for the owners' meeting","scenario":"Both owners, thirty minutes, once a quarter — and this quarter you need three decisions: the patio investment, the assistant-manager hire, and the holiday closure dates. One page, read in four minutes, structured so each decision is make-able on the spot.","task":"Write the one-pager: the quarter's verdict line, then three decision blocks each with ask, number, and recommendation.","tips":["One verdict line on the quarter up top — context in a single sentence, not a section.","Each block is identical in shape: THE ASK, THE MATH, MY RECOMMENDATION. Sameness of structure speeds three decisions.","Rank them: the one that's time-sensitive is labeled 'decide today'; the others can survive a week."],"focus":["structure","concision"],"placeholder":"Q3 in one line: up 8%, fully staffed, one machine risk. Three decisions today — the first is time-sensitive."},
    {"id":"together-svc-mid-24","level":"mid","profession":"service","title":"Same news, two channels","scenario":"The store is being acquired by a small regional group. Staff hear it first in the group chat tonight (fast, human, rumor-beating); the formal letter follows tomorrow (complete, precise, on the record). Two versions of one message — register-matched to each channel, contradicting nothing.","task":"Write both: the 60-word group-chat message and the opening paragraph of the formal letter.","tips":["Chat version: the fact, the immediate reassurance (jobs, pay, schedules unchanged), and where fuller answers come tomorrow.","Letter version: complete and precise — the acquirer named, the date, what's confirmed versus still being worked out, labeled honestly.","The two must match on every fact; the chat compresses, it never shades."],"focus":["audience","clarity"],"placeholder":"Big news you should hear from me first: the store is being bought by the Fielding group. Your jobs, pay, and schedules don't change —"},
    {"id":"together-svc-mid-25","level":"mid","profession":"service","title":"The send-button checklist","scenario":"Tomorrow morning you send the most consequential email of your year: the proposal asking the owner to make you general manager of both locations. Tonight, the last skill: editing your own draft against everything — point first? audience-shaped? precise? concise? owned? objection met?","task":"Write your six-question pre-send checklist, then apply it: name the two edits your real draft would most likely need.","tips":["Build the checklist from the failures you know you make — buried asks, hedged verdicts, unpriced requests.","Apply it ruthlessly: most drafts fail on 'is the ask in line one' and 'did I state the number.'","The discipline is the deliverable: the checklist you'd actually run at 11pm, tired, on your own words."],"focus":["structure","impact"],"placeholder":"Before sending: 1) Is the ask the first sentence? 2) Is every claim a number where a number exists?"}
  ]
};
